// The fat-station `/generate` call blocks until the WHOLE forward completes and
// only THEN sends response headers. For gemma4-12b on the L4 the forward can run
// 300-600s (R2 Range weight streaming ~5-6s/layer), but undici's default
// `headersTimeout` is 300s — so the fetch threw `TypeError: fetch failed`,
// surfaced as garbage/retries and made every slow GPU forward un-observable.
// Raise the global dispatcher's timeouts to 900s using the existing dispatcher's
// own constructor (no `undici` import — it is not a resolvable module here).
try {
  const sym = Symbol.for('undici.globalDispatcher.1');
  const cur = (globalThis as unknown as Record<symbol, unknown>)[sym] as
    | { constructor: new (opts: unknown) => unknown }
    | undefined;
  if (cur && typeof cur.constructor === 'function') {
    const AgentCtor = cur.constructor as new (opts: unknown) => unknown;
    (globalThis as unknown as Record<symbol, unknown>)[sym] = new AgentCtor({
      headersTimeout: 900_000,
      bodyTimeout: 900_000,
      connectTimeout: 60_000,
    });
    console.log('[openai-server] raised undici headers/body timeout to 900s for slow forwards');
  }
} catch (e) {
  console.warn('[openai-server] could not raise undici timeout (continuing):', e);
}

