// Env mode now DEFAULTS TO 'off' (see parseTerminalProsodyMode) — terminal
// prosody is opt-in-only until the prosody-speed work lands. With an unset env
// this is 'off', so the pipeline is constructed WITHOUT prosody config and no
// consumer can accidentally trigger the slow ~15-19s/step biasing phase.
const TERMINAL_PROSODY_MODE = parseTerminalProsodyMode(process.env['TERMINAL_PROSODY']);

/**
 * Resolve whether terminal-prosody biasing should run for a single request.
 *
 * Polarity is DEFAULT OFF / opt-in (until the prosody-speed work lands):
 *   prosody_on = !suppress_prosody &&
 *                (req.enable_prosody === true ||
 *                 req.terminal_prosody is bias/observe ||
 *                 envMode !== 'off')
 * with envMode (TERMINAL_PROSODY) defaulting to 'off'.
 *
 * `suppress_prosody:true` always wins (belt-and-suspenders for text consumers
 * like the wiki generator). Returns a flag the callers translate into the
 * pipeline's per-request `suppressTerminalProsody` and into whether the song /
 * prefill-window (prosody-bearing) path may be taken at all.
 */
function resolveRequestProsodyOn(req: {
  suppress_prosody?: boolean;
  enable_prosody?: boolean;
  terminal_prosody?: 'off' | 'observe' | 'bias';
}): boolean {
  if (req.suppress_prosody === true) {
    return false;
  }
  const reqMode = req.terminal_prosody;
  const reqOptIn =
    req.enable_prosody === true || reqMode === 'bias' || reqMode === 'observe';
  if (reqMode === 'off') {
    // Explicit per-request off also disables, regardless of env.
    return false;
  }
  return reqOptIn || TERMINAL_PROSODY_MODE !== 'off';
}

