/**
 * Liquid memory + KV-session reuse is only beneficial when the station actually
 * implements the `/kv-session/save|load|delete` routes. If the station lacks
 * them (e.g. a STALE `fat-station-cuda` binary baked into an older GPU image),
 * every `saveKvSession` 404s and the liquid path falls to the slow
 * host-orchestrated per-token decode (observed: 0.58 tok/s vs the 7 tok/s native
 * `/generate` baseline). So we probe the capability at boot and disable liquid
 * memory when it is missing — serving via the fast native path instead of
 * silently degrading. See LIQUID_MEMORY_KV_SAVE.md.
 *
 * Two signals, in order of trust:
 *  1. `/health` advertises `kv_session: true` (current source does this).
 *  2. Active probe: POST `/kv-session/save` with prefix_len=0. A capable station
 *     answers 200; a stale binary returns 404. This is the ground truth and
 *     self-heals even when `/health` predates the capability flag.
 */
async function probeKvSessionSupport(healthBody: Record<string, unknown>): Promise<boolean> {
  // Trust an explicit negative flag from /health immediately.
  if (healthBody['kv_session'] === false) return false;
  try {
    const res = await fetch(`${FAT_STATION_URL}/kv-session/save`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/octet-stream',
        'X-Session-Id': 'liquid_capability_probe',
        'X-Prefix-Length': '0',
        'X-Request-Id': 'capability-probe',
      },
      body: new ArrayBuffer(0),
    });
    // 404 => route absent (stale binary). Any 2xx => route present. Other codes
    // (e.g. 400/500 on a prefix_len=0 edge) still prove the route EXISTS, so we
    // treat anything that is not a 404 as "supported".
    if (res.status === 404) return false;
    // Best-effort cleanup of the probe session so it never occupies the
    // capacity-1 KV store. Ignore failures.
    try {
      await fetch(`${FAT_STATION_URL}/kv-session/delete`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/octet-stream',
          'X-Session-Id': 'liquid_capability_probe',
          'X-Request-Id': 'capability-probe-cleanup',
        },
        body: new ArrayBuffer(0),
      });
    } catch {
      /* ignore */
    }
    return true;
  } catch {
    // Network/parse error talking to the station: be conservative and treat KV
    // sessions as unsupported so we stay on the fast native path.
    return false;
  }
}

async function probeFatStation(): Promise<{
  hiddenDim: number;
  vocabSize: number;
  layers: string;
  maxSeqLen: number;
  altArch: boolean;
  arch: string;
  kvSession: boolean;
}> {
  const res = await fetch(`${FAT_STATION_URL}/health`);
  if (!res.ok) throw new Error(`fat-station health check failed: ${res.status}`);
  const body = (await res.json()) as Record<string, unknown>;
  return {
    hiddenDim: (body['hidden_dim'] as number) ?? 2048,
    vocabSize: (body['vocab_size'] as number) ?? 32000,
    layers: (body['layers'] as string) ?? '0-22',
    // Max sequence length (KV slab capacity) reported by the station; bounds the
    // effective prompt-token ceiling clients must respect.
    maxSeqLen: (body['max_seq_len'] as number) ?? 8192,
    // Non-transformer knots (gemma/mamba/rwkv7/qwen35moe) only serve /generate; the
    // /embed-based liquid-memory + prefill-window paths panic on them. Default false
    // for older fat-station images that don't report it (transformer is the common case).
    altArch: body['alt_arch'] === true,
    arch: (body['arch'] as string) ?? 'transformer',
    // KV-session reuse capability (drives liquid-memory gating below).
    kvSession: await probeKvSessionSupport(body),
  };
}

function parseLayerRange(s: string): { start: number; end: number } {
  const m = s.match(/(\d+)-(\d+)/);
  return m ? { start: parseInt(m[1]!), end: parseInt(m[2]!) } : { start: 0, end: 22 };
}

function safeLlamaDecode(tokenIds: readonly number[]): string {
  try {
    return LlamaTokenizer.decode([...tokenIds]) as string;
  } catch {
    return '';
  }
}

function createLlamaTokenizer(): TextTokenizer {
  return {
    name: 'llama',
    stopTokenIds: [1, 2],
    encodePrompt(text: string): number[] {
      return LlamaTokenizer.encode(text, true, false) as number[];
    },
    encodeText(text: string): number[] {
      return LlamaTokenizer.encode(text, false, false) as number[];
    },
    decode(tokenIds: readonly number[]): string {
      return safeLlamaDecode(tokenIds);
    },
    decodeToken(tokenId: number): string {
      return safeLlamaDecode([tokenId]);
    },
  };
}

function isQwenModelName(modelName = MODEL_NAME): boolean {
  return modelName.toLowerCase().includes('qwen');
}

function isMistralV3ModelName(modelName = MODEL_NAME): boolean {
  const normalized = modelName.toLowerCase();
  return normalized.includes('mistral') && normalized.includes('v0.3');
}

function parseTokenizerFamily(value: string | undefined): TokenizerFamily | null {
  if (!value) return null;
  const normalized = value.trim().toLowerCase();
  if (normalized === 'llama' || normalized === 'llama2') return 'llama';
  if (normalized === 'qwen' || normalized === 'qwen2') return 'qwen2';
  if (
    normalized === 'hf-bpe-metaspace' ||
    normalized === 'hf_bpe_metaspace' ||
    normalized === 'mistral-v3' ||
    normalized === 'mistral_v3'
  ) {
    return 'hf-bpe-metaspace';
  }
  throw new Error(
    `unsupported TOKENIZER_FAMILY=${value}; expected llama, qwen2, or hf-bpe-metaspace`,
  );
}

function inferTokenizerFamily(): TokenizerFamily {
  const explicit = parseTokenizerFamily(TOKENIZER_FAMILY);
  if (explicit) return explicit;
  if (TOKENIZER_JSON_PATH || TOKENIZER_JSON_URL || isMistralV3ModelName()) {
    return 'hf-bpe-metaspace';
  }
  if (isQwenModelName() || resolveQwenTokenizerPath() !== null) return 'qwen2';
  return 'llama';
}

function resolveQwenTokenizerPath(): string | null {
  if (TOKENIZER_JSON_PATH && existsSync(TOKENIZER_JSON_PATH)) {
    return TOKENIZER_JSON_PATH;
  }

  if (TOKENIZER_GGUF_PATH && existsSync(TOKENIZER_GGUF_PATH)) {
    return TOKENIZER_GGUF_PATH;
  }

  if (!AUX_KNOT_PATH) return null;

  const knotBaseName = basename(AUX_KNOT_PATH, '.knot');
  const adjacentGgufPath = join(
    dirname(AUX_KNOT_PATH),
    'gguf',
    `${knotBaseName}.gguf`
  );
  return existsSync(adjacentGgufPath) ? adjacentGgufPath : null;
}

async function createHfBpeMetaspaceTextTokenizer(): Promise<TextTokenizer> {
  const name = 'hf-bpe-metaspace';
  const tokenizer = TOKENIZER_JSON_PATH
    ? loadHfBpeMetaspaceTokenizerFromFile(TOKENIZER_JSON_PATH, name)
    : TOKENIZER_JSON_URL
      ? await loadHfBpeMetaspaceTokenizerFromUrl(TOKENIZER_JSON_URL, name)
      : null;

  if (!tokenizer) {
    throw new Error(
      'hf-bpe-metaspace tokenizer selected but TOKENIZER_JSON_PATH or TOKENIZER_JSON_URL is not configured',
    );
  }

  return {
    name,
    stopTokenIds: tokenizer.stopTokenIds,
    encodePrompt(text: string): number[] {
      return tokenizer.encode(text, { addBos: true });
    },
    encodeText(text: string): number[] {
      return tokenizer.encode(text, { addBos: false });
    },
    decode(tokenIds: readonly number[]): string {
      return tokenizer.decode(tokenIds, { skipSpecial: true });
    },
    decodeToken(tokenId: number): string {
      return tokenizer.decodeToken(tokenId);
    },
  };
}

async function createTextTokenizer(): Promise<TextTokenizer> {
  const family = inferTokenizerFamily();
  if (family === 'llama') return createLlamaTokenizer();
  if (family === 'hf-bpe-metaspace') return createHfBpeMetaspaceTextTokenizer();

  const tokenizerPath = resolveQwenTokenizerPath();
  if (!tokenizerPath) {
    throw new Error(
      'Qwen model selected but no Qwen tokenizer was found. Set TOKENIZER_JSON_PATH or TOKENIZER_GGUF_PATH; refusing to fall back to the Llama tokenizer.',
    );
  }

  const qwenTokenizer = tokenizerPath.endsWith('.json')
    ? loadQwenTokenizerFromJson(tokenizerPath)
    : loadQwenTokenizerFromGguf(tokenizerPath);
  console.log(`[openai-server] loaded Qwen tokenizer: ${tokenizerPath}`);
  return {
    name: 'qwen2',
    stopTokenIds: qwenTokenizer.stopTokenIds,
    encodePrompt(text: string): number[] {
      return qwenTokenizer.encode(text);
    },
    encodeText(text: string): number[] {
      return qwenTokenizer.encode(text);
    },
    decode(tokenIds: readonly number[]): string {
      return qwenTokenizer.decode(tokenIds);
    },
    decodeToken(tokenId: number): string {
      return qwenTokenizer.decode([tokenId]);
    },
  };
}

function collectSentenceCloseTokenIds(tokenizer: TextTokenizer): number[] {
  const ids = new Set<number>();
  // NOTE: a newline is NOT a sentence close. Including '\n' here let the
  // terminal-prosody controller treat a line-break as SentenceClosed, so it
  // emitted EOS right after a comma-ending poem line ("...the wind whispers,\n").
  // With '\n' removed, a newline is a continuation and defer-stop (default true)
  // holds EOS until a real . ! ? — poems end on a period, not on a comma.
  for (const text of ['.', '!', '?', ' .', ' !', ' ?']) {
    try {
      for (const tokenId of tokenizer.encodeText(text)) {
        ids.add(tokenId);
      }
    } catch {
      // Runtime decoding still classifies punctuation when an id is not in
      // this compact tokenizer-specific set.
    }
  }
  return [...ids];
}

// TinyLlama / Llama-2 chat template.
// `tool_calls`/`tool_call_id`/`name` are optional and only populated/consumed
// by chat templates with a native tool-calling format (see
// canUseFamilyChatTemplate/applyQwenChatTemplate) — every other template
// ignores them exactly as before.
type Message = {
  role: string;
  content: string;
  tool_calls?: AgenticToolCall[];
  tool_call_id?: string;
  name?: string;
};

function applyLlama2ChatTemplate(messages: Message[]): string {
  let result = '';
  let systemPrompt = '';
  for (const msg of messages) {
    if (msg.role === 'system') systemPrompt = msg.content;
  }
  const turns: Array<{ user: string; assistant: string | null }> = [];
  let pendingUser: string | null = null;
  for (const msg of messages) {
    if (msg.role === 'system') continue;
    if (msg.role === 'user') {
      if (pendingUser !== null) turns.push({ user: pendingUser, assistant: null });
      pendingUser = msg.content;
    } else if (msg.role === 'assistant') {
      turns.push({ user: pendingUser ?? '', assistant: msg.content });
      pendingUser = null;
    }
  }
  if (pendingUser !== null) turns.push({ user: pendingUser, assistant: null });
  for (let i = 0; i < turns.length; i++) {
    const turn = turns[i]!;
    let userPart = turn.user;
    if (i === 0 && systemPrompt) userPart = `<<SYS>>\n${systemPrompt}\n<</SYS>>\n\n${userPart}`;
    result += `<s>[INST] ${userPart} [/INST]`;
    if (turn.assistant !== null) result += ` ${turn.assistant}</s>`;
  }
  return result;
}

// Llama-3 instruct format (header tokens + <|eot_id|>). The 'llama2' template
// emits [INST] … [/INST], which a Llama-3 finetune (e.g. loki-8b-erotica) was
// NOT tuned on — it produces degraded/rambling output. This renders the real
// Llama-3 chat header structure the model expects.
function applyLlama3ChatTemplate(messages: Message[]): string {
  const header = (role: string, content: string) =>
    `<|start_header_id|>${role}<|end_header_id|>\n\n${content}<|eot_id|>`;
  let result = '<|begin_of_text|>';
  for (const msg of messages) {
    if (msg.role === 'system') result += header('system', msg.content);
  }
  for (const msg of messages) {
    if (msg.role === 'user') result += header('user', msg.content);
    else if (msg.role === 'assistant') result += header('assistant', msg.content);
  }
  // Open the assistant turn for generation.
  result += '<|start_header_id|>assistant<|end_header_id|>\n\n';
  return result;
}

function applyQwenChatTemplate(messages: Message[]): string {
  let result = '';
  for (const msg of messages) {
    if (msg.role === 'tool') {
      // Qwen's real template renders tool results as a `user`-role turn
      // wrapping each result in <tool_response>...</tool_response>.
      result += `<|im_start|>user\n${formatQwenToolResultTurn(msg.content)}<|im_end|>\n`;
      continue;
    }
    if (msg.role === 'assistant' && msg.tool_calls && msg.tool_calls.length > 0) {
      const callBlock = formatQwenAssistantToolCallTurn(msg.tool_calls);
      const content = msg.content ? `${msg.content}\n${callBlock}` : callBlock;
      result += `<|im_start|>assistant\n${content}<|im_end|>\n`;
      continue;
    }
    result += `<|im_start|>${msg.role}\n${msg.content}<|im_end|>\n`;
  }
  return `${result}<|im_start|>assistant\n`;
}

// Gemma 2/3/4 instruct chat template. Gemma has no dedicated `system` role:
// HF's chat template folds any leading system content into the first user turn
// (separated by a blank line). Each turn is wrapped in
// `<start_of_turn>{role}\n{content}<end_of_turn>\n`, with `user`/`model` as the
// only roles (assistant → model), and the prompt is closed with an open
// `<start_of_turn>model\n` so the model generates the reply.
function applyGemmaChatTemplate(messages: Message[]): string {
  let systemPrompt = '';
  for (const msg of messages) {
    if (msg.role === 'system') systemPrompt = msg.content;
  }
  let result = '<bos>';
  let firstUserSeen = false;
  for (const msg of messages) {
    if (msg.role === 'system') continue;
    const role = msg.role === 'assistant' ? 'model' : 'user';
    let content = msg.content;
    if (role === 'user' && !firstUserSeen) {
      firstUserSeen = true;
      if (systemPrompt) content = `${systemPrompt}\n\n${content}`;
    }
    result += `<start_of_turn>${role}\n${content}<end_of_turn>\n`;
  }
  result += '<start_of_turn>model\n';
  return result;
}

// Gemma 4 (gemma4_unified) instruct chat template. UNLIKE gemma 2/3 this arch
// uses `<|turn>{role}\n{content}<turn|>\n` framing (NOT `<start_of_turn>` —
// different special-token ids 105/106) and is a REASONING model: the assistant
// turn opens a thought channel `<|channel>thought\n<channel|>`. Feeding the
// gemma-2/3 template to gemma4_unified produces special-token salad (the model
// never enters the answer state) — verified against the HF reference forward
// (right template → 'Paris'=50429 @ +20 logits; gemma-3 framing → `<|channel>`
// /`<channel|>`/`thought` garbage on the SAME weights).
function applyGemma4ChatTemplate(messages: Message[]): string {
  let systemPrompt = '';
  for (const msg of messages) {
    if (msg.role === 'system') systemPrompt = msg.content;
  }
  // NOTE: no leading '<bos>' here — encodePrompt() calls encode(addBos:true)
  // which unconditionally prepends the BOS id. Emitting a literal '<bos>'
  // (a `special` token in the gemma4 tokenizer) would DOUBLE the BOS
  // (28 tokens vs HF's 27 for the France probe), shifting the model
  // off-distribution. The HF reference uses a single BOS.
  let result = '';
  let firstUserSeen = false;
  for (const msg of messages) {
    if (msg.role === 'system') continue;
    // EXPERIMENTAL (GEMMA4_NATIVE_TOOLS_EXPERIMENTAL): tool/tool_calls turns
    // only ever reach here when canUseFamilyChatTemplate already gated on
    // isNativeToolChatTemplate — every other caller keeps the exact
    // plain-chat behavior below unchanged.
    if (msg.role === 'tool') {
      result += `<|turn>user\n${formatGemma4ToolResultTurn(msg.content, msg.name ?? 'unknown')}<turn|>\n`;
      continue;
    }
    if (msg.role === 'assistant' && msg.tool_calls && msg.tool_calls.length > 0) {
      const callBlock = formatGemma4ToolCallTurn(msg.tool_calls);
      const content = msg.content ? `${msg.content}\n${callBlock}` : callBlock;
      result += `<|turn>model\n${content}<turn|>\n`;
      continue;
    }
    const role = msg.role === 'assistant' ? 'model' : 'user';
    let content = msg.content;
    if (role === 'user' && !firstUserSeen) {
      firstUserSeen = true;
      if (systemPrompt) content = `${systemPrompt}\n\n${content}`;
    }
    result += `<|turn>${role}\n${content}<turn|>\n`;
  }
  result += '<|turn>model\n<|channel>thought\n<channel|>';
  return result;
}

// Zephyr / TinyLlama-Chat template. TinyLlama-1.1B-Chat-v1.0 (and the Zephyr
// SFT lineage) was NOT trained on Llama-2 `[INST]`; it uses
// `<|user|>\n{content}</s>\n<|assistant|>\n{content}</s>\n...` and closes with
// an open `<|assistant|>\n` for generation. `</s>` (EOS id 2) is already a
// llama-tokenizer stop token. Using `[INST]` here produces off-distribution
// output (the symptom: incoherent replies like "- [Slide]" to a Paris prompt).
// Base/completion passthrough: no role markers, no chat special tokens, no
// assistant suffix. The model simply continues the concatenated prompt text —
// the correct framing for un-instruction-tuned base LMs (e.g. state-spaces
// mamba-2.8b, tiiuae falcon-mamba-7b base) whose vocab has none of the chat
// markers. Contents are joined with newlines to preserve multi-message prompts.
function applyRawCompletionTemplate(messages: Message[]): string {
  return messages
    .map((msg) => msg.content)
    .filter((content) => content.length > 0)
    .join('\n');
}

function applyZephyrChatTemplate(messages: Message[]): string {
  let result = '';
  for (const msg of messages) {
    const role =
      msg.role === 'assistant'
        ? 'assistant'
        : msg.role === 'system'
          ? 'system'
          : 'user';
    result += `<|${role}|>\n${msg.content}</s>\n`;
  }
  result += '<|assistant|>\n';
  return result;
}

// The full renderer (including the tool round-trip: [AVAILABLE_TOOLS]
// preamble, [TOOL_CALLS]/[TOOL_RESULTS] segments) lives in
// native-tool-formats.ts's renderMistralV3InstructPrompt — see that
// function's doc comment for why (this file cannot be safely unit-tested by
// direct import, since it calls main() unconditionally at module scope).
function applyMistralV3InstructTemplate(
  messages: Message[],
  tools?: AgenticToolDefinition[],
): string {
  return renderMistralV3InstructPrompt(messages, tools);
}

function normalizeMessageContent(content: unknown): string {
  return typeof content === 'string' ? content : '';
}

/** Chat templates whose renderer knows how to place a `role: 'tool'` message
 * (native tool-calling families). Everything else keeps today's exact
 * behavior: any tool-role message forces the generic fallback wrapper. */
function isNativeToolChatTemplate(chatTemplate: ChatTemplate): boolean {
  if (!NATIVE_TOOL_CALLING_ENABLED) return false;
  if (chatTemplate === 'qwen-chatml') return true;
  if (chatTemplate === 'mistral-v3-instruct') return true;
  if (chatTemplate === 'gemma4') return GEMMA4_NATIVE_TOOLS_EXPERIMENTAL;
  return false;
}

function canUseFamilyChatTemplate(
  messages: readonly Message[],
  chatTemplate: ChatTemplate,
): boolean {
  const allowToolRole = isNativeToolChatTemplate(chatTemplate);
  return messages.every(
    (message) =>
      message.role === 'system' ||
      message.role === 'user' ||
      message.role === 'assistant' ||
      (allowToolRole && message.role === 'tool'),
  );
}

function parseChatTemplate(value: string | undefined): ChatTemplate | null {
  if (!value) return null;
  const normalized = value.trim().toLowerCase();
  if (normalized === 'llama3' || normalized === 'llama-3' || normalized === 'llama3-instruct') {
    return 'llama3';
  }
  if (normalized === 'llama2' || normalized === 'llama') return 'llama2';
  if (normalized === 'qwen-chatml' || normalized === 'qwen2' || normalized === 'chatml') {
    return 'qwen-chatml';
  }
  if (
    normalized === 'mistral-v3-instruct' ||
    normalized === 'mistral_v3_instruct' ||
    normalized === 'mistral-instruct'
  ) {
    return 'mistral-v3-instruct';
  }
  if (normalized === 'gemma' || normalized === 'gemma2' || normalized === 'gemma3') {
    return 'gemma';
  }
  if (normalized === 'gemma4' || normalized === 'gemma4-unified') {
    return 'gemma4';
  }
  if (
    normalized === 'zephyr' ||
    normalized === 'tinyllama' ||
    normalized === 'tinyllama-chat'
  ) {
    return 'zephyr';
  }
  if (
    normalized === 'raw' ||
    normalized === 'none' ||
    normalized === 'completion' ||
    normalized === 'base'
  ) {
    return 'raw';
  }
  throw new Error(
    `unsupported CHAT_TEMPLATE=${value}; expected llama2, llama3, qwen-chatml, mistral-v3-instruct, gemma, gemma4, zephyr, or raw`,
  );
}

function resolveChatTemplate(tokenizer: TextTokenizer): ChatTemplate {
  const explicit = parseChatTemplate(CHAT_TEMPLATE);
  if (explicit) return explicit;
  if (tokenizer.name === 'qwen2') return 'qwen-chatml';
  if (tokenizer.name === 'hf-bpe-metaspace' || isMistralV3ModelName()) {
    return 'mistral-v3-instruct';
  }
  return 'llama2';
}

/** Normalizes a message for template rendering, preserving `tool_calls`/
 * `tool_call_id`/`name` — every renderer still ignores these unless it has a
 * native tool-calling branch (currently only `applyQwenChatTemplate`). */
function toRenderMessage(message: Message): Message {
  return {
    role: message.role,
    content: normalizeMessageContent(message.content),
    ...(message.tool_calls ? { tool_calls: message.tool_calls } : {}),
    ...(message.tool_call_id ? { tool_call_id: message.tool_call_id } : {}),
    ...(message.name ? { name: message.name } : {}),
  };
}

function renderPromptForGeneration(
  messages: readonly Message[],
  chatTemplate: ChatTemplate,
  // Only the Mistral V3 branch consumes this (its [AVAILABLE_TOOLS] segment
  // sits before the first [INST] turn, outside any message's content); every
  // other template ignores it exactly as before.
  tools?: AgenticToolDefinition[],
): string {
  // Base/completion models: pass the prompt through verbatim regardless of role
  // shape (checked before canUseFamilyChatTemplate so tool/other roles still stay
  // unwrapped rather than falling to the `<s>[INST]` default).
  if (chatTemplate === 'raw') {
    return applyRawCompletionTemplate(messages.map(toRenderMessage));
  }
  if (canUseFamilyChatTemplate(messages, chatTemplate)) {
    if (chatTemplate === 'qwen-chatml') {
      return applyQwenChatTemplate(messages.map(toRenderMessage));
    }

    if (chatTemplate === 'gemma') {
      return applyGemmaChatTemplate(messages.map(toRenderMessage));
    }

    if (chatTemplate === 'gemma4') {
      return applyGemma4ChatTemplate(messages.map(toRenderMessage));
    }

    if (chatTemplate === 'mistral-v3-instruct') {
      return applyMistralV3InstructTemplate(messages.map(toRenderMessage), tools);
    }

    if (chatTemplate === 'zephyr') {
      return applyZephyrChatTemplate(messages.map(toRenderMessage));
    }

    if (chatTemplate === 'llama3') {
      return applyLlama3ChatTemplate(messages.map(toRenderMessage));
    }

    return applyLlama2ChatTemplate(messages.map(toRenderMessage));
  }

  const rendered = renderMessagesForPrompt(
    messages.map((message) => ({
      role: message.role as AgenticChatMessage['role'],
      content: normalizeMessageContent(message.content),
    })),
  );
  return `<s>[INST] ${rendered} [/INST]`;
}

function promptTokensForLocalInference(
  tokenizer: TextTokenizer,
  chatTemplate: ChatTemplate,
  messages: readonly Message[],
  tools?: AgenticToolDefinition[],
): number[] {
  const tokens = tokenizer.encodePrompt(renderPromptForGeneration(messages, chatTemplate, tools));
  if (process.env['MOONSHINE_LOG_PROMPT_TOKENS']) {
    console.error(`[tokdbg] template=${chatTemplate} n=${tokens.length} ids=${JSON.stringify(tokens)}`);
  }
  if (
    Number.isFinite(MAX_PROMPT_TOKENS) &&
    MAX_PROMPT_TOKENS > 0 &&
    tokens.length > MAX_PROMPT_TOKENS
  ) {
    return tokens.slice(tokens.length - MAX_PROMPT_TOKENS);
  }
  return tokens;
}

const CHAT_TEMPLATE_PREFIXES = [
  '<s>[INST]',
  '[INST]',
  '<s>',
  '</s>',
  '[/INST]',
  '[SING]',
  '<<SYS>>',
  '<</SYS>>',
  '<|im_start|>',
  '<|im_end|>',
  '<|endoftext|>',
  '<start_of_turn>',
  '<end_of_turn>',
  '<|turn>',
  '<turn|>',
  '<|channel>',
  '<channel|>',
  '<bos>',
  '<eos>',
  '<|user|>',
  '<|assistant|>',
  '<|system|>',
];

/** True when streamed text may be a partial chat-template control marker. */
function isPendingChatTemplatePrefix(text: string): boolean {
  const trimmed = text.trimStart();
  if (!trimmed) return false;
  for (const prefix of CHAT_TEMPLATE_PREFIXES) {
    if (prefix.startsWith(trimmed)) return true;
  }
  return false;
}

/** Remove generated Llama chat-template echoes from assistant text. */
/**
 * Strip a trailing run of degenerate terminal punctuation — models frequently
 * ramble into "..." / " . . . . ." at the end of a reply (punctuation terminal
 * prosody). We "stop at ...": trim a trailing run of ≥3 dots (spaces allowed
 * between) or any ellipsis run. Mid-text ellipses are preserved — only the tail
 * is stripped. Applied per-token while streaming (the tail simply never emits,
 * and re-emits if real text follows) and to the final non-streaming content.
 */
function stripDegenerateTail(text: string): string {
  return text.replace(/(?:\s*\.){3,}\s*$/u, '').replace(/\s*…+\s*$/u, '');
}

function trimAfterFirstCompleteCodeFence(text: string): string {
  const first = text.indexOf('```');
  if (first < 0) return text;
  const afterOpenLine = text.indexOf('\n', first + 3);
  if (afterOpenLine < 0) return text;
  const close = text.indexOf('```', afterOpenLine + 1);
  if (close < 0) return text;
  return text.slice(0, close + 3).trimEnd();
}

function stripGeneratedChatTemplateEcho(text: string): string {
  let remaining = text;

  while (remaining.length > 0) {
    remaining = remaining.trimStart();

    if (remaining.startsWith('<s>[INST]')) {
      const closeIndex = remaining.indexOf('[/INST]');
      if (closeIndex < 0) return '';
      remaining = remaining.slice(closeIndex + '[/INST]'.length);
      continue;
    }

    if (remaining.startsWith('[INST]')) {
      const closeIndex = remaining.indexOf('[/INST]');
      if (closeIndex < 0) return '';
      remaining = remaining.slice(closeIndex + '[/INST]'.length);
      continue;
    }

    if (remaining.startsWith('<|im_start|>')) {
      const closeIndex = remaining.indexOf('<|im_end|>');
      if (closeIndex < 0) return '';
      remaining = remaining.slice(closeIndex + '<|im_end|>'.length);
      continue;
    }

    // Zephyr / TinyLlama-Chat: drop any echoed <|user|>/<|system|> turn (closed
    // by </s>), and strip a leading <|assistant|> open marker.
    if (
      remaining.startsWith('<|user|>') ||
      remaining.startsWith('<|system|>')
    ) {
      const closeIndex = remaining.indexOf('</s>');
      if (closeIndex < 0) return '';
      remaining = remaining.slice(closeIndex + '</s>'.length);
      continue;
    }
    if (remaining.startsWith('<|assistant|>')) {
      remaining = remaining.slice('<|assistant|>'.length);
      continue;
    }

    if (remaining.startsWith('assistant\n')) {
      remaining = remaining.slice('assistant\n'.length);
      continue;
    }

    let removedMarker = false;
    for (const marker of [
      '<s>',
      '</s>',
      '[/INST]',
      '[SING]',
      '<<SYS>>',
      '<</SYS>>',
      '<|im_end|>',
      '<|endoftext|>',
    ]) {
      if (remaining.startsWith(marker)) {
        remaining = remaining.slice(marker.length);
        removedMarker = true;
        break;
      }
    }
    if (removedMarker) continue;

    if (isPendingChatTemplatePrefix(remaining)) return '';
    return remaining;
  }

  return '';
}

function buildRuntime(
  pipeline: Pipeline,
  tokenizer: TextTokenizer,
  chatTemplate: ChatTemplate,
  auxRuntime?: LocalKnotRuntime,
  options: { agentic: boolean; mcpUrl?: string } = { agentic: DEFAULT_AGENTIC },
  defaultMcpClient?: AgenticMcpClient,
): AgenticChatRuntime {
  const useSingleton = options.agentic && (!options.mcpUrl || options.mcpUrl === MCP_URL);
  const mcp = options.agentic
    ? (useSingleton && defaultMcpClient
        ? defaultMcpClient
        : createSuperserverMcpClient({
            mcpUrl: options.mcpUrl ?? MCP_URL,
            ...(MCP_AUTH_TOKEN ? { authToken: MCP_AUTH_TOKEN } : {}),
          }))
    : undefined;

  const nativeToolFamily = NATIVE_TOOL_CALLING_ENABLED
    ? resolveNativeToolFamily(chatTemplate, { gemma4Enabled: GEMMA4_NATIVE_TOOLS_EXPERIMENTAL })
    : null;

  return {
    mcp,
    nativeToolFamily,
    ...(THOTH_OATH_LEDGER_STORE
      ? { thothOathLedgerStore: THOTH_OATH_LEDGER_STORE }
      : {}),
    ...(THOTH_PLACE_SIM_HOST
      ? { thothPlaceSimHost: THOTH_PLACE_SIM_HOST }
      : {}),

    async infer(request: TextGenerationRequest): Promise<TextGenerationResult> {
      // Aux purposes (intent-evaluation, tool-review, tool-args, tool-retry) route to the
      // in-process LocalKnotRuntime when available — eliminates HTTP round-trips for small
      // decision tasks that don't need the full fat-station quality.
      if (request.purpose !== 'chat' && auxRuntime) {
        return auxRuntime.infer(request);
      }

      // Chat (and aux fallback when no knot configured) → fat-station Pipeline.
      const promptMessages: Message[] = request.messages.map((message) => ({
        role: message.role,
        content: normalizeMessageContent(message.content),
        ...(message.tool_calls ? { tool_calls: message.tool_calls } : {}),
        ...(message.tool_call_id ? { tool_call_id: message.tool_call_id } : {}),
        ...(message.name ? { name: message.name } : {}),
      }));
      const promptTokens = promptTokensForLocalInference(
        tokenizer,
        chatTemplate,
        promptMessages,
        request.tools,
      );
      const maxNew = request.maxTokens ?? DEFAULT_MAX_NEW_TOKENS;

      const allTokens = await pipeline.generate({
        promptTokens: new Uint32Array(promptTokens),
        maxNewTokens: maxNew,
        // Internal agentic/aux inference — never the voice path, so prosody is
        // suppressed (DEFAULT OFF / opt-in). The pipeline now always carries the
        // prosody capability config, so this must be explicit, not implicit.
        suppressTerminalProsody: true,
      });
      const newTokens = Array.from(allTokens.slice(promptTokens.length));
      const content = stripGeneratedChatTemplateEcho(
        tokenizer.decode(newTokens),
      ).trim();

      return {
        content,
        promptTokens: promptTokens.length,
        completionTokens: newTokens.length,
        model: MODEL_NAME,
      };
    },

    logger: console,
  };
}

async function handleThothOathAudit(): Promise<ChatCompletionResult> {
  if (!THOTH_OATH_LEDGER_STORE) {
    return thothOathLedgerNotConfigured();
  }
  const records = await THOTH_OATH_LEDGER_STORE.load();
  const now = Date.now();
  const oaths = records.map((record) => ({
    ...record,
    effectiveStatus: thothOathEffectiveStatus(record, now),
    remainingMs: Math.max(0, record.expiresAt - now),
  }));
  return {
    status: 200,
    body: JSON.stringify({
      object: 'thoth.oath_ledger',
      ledgerPath: THOTH_OATH_LEDGER_STORE.path,
      nonAuthoritative: true,
      oaths,
      activeOathCount: oaths.filter((record) => record.effectiveStatus === 'active')
        .length,
    }),
  };
}

async function handleThothOathCreate(body: string): Promise<ChatCompletionResult> {
  if (!THOTH_OATH_LEDGER_STORE) {
    return thothOathLedgerNotConfigured();
  }
  const input = parseJsonRecord(body);
  if (!input.ok) return input;
  const client = createThothOathSelfManagementMcpClient({
    ledgerStore: THOTH_OATH_LEDGER_STORE,
  });
  const result = await client.callTool(THOTH_OATH_PROPOSE_TOOL, input.value);
  return {
    status: result.success ? 201 : 400,
    body: JSON.stringify(result.success ? result.result : { error: result.error }),
  };
}

async function handleThothOathPatch(
  id: string,
  body: string,
): Promise<ChatCompletionResult> {
  if (!THOTH_OATH_LEDGER_STORE) {
    return thothOathLedgerNotConfigured();
  }
  const input = parseJsonRecord(body);
  if (!input.ok) return input;
  const records = [...(await THOTH_OATH_LEDGER_STORE.load())];
  const index = records.findIndex((record) => record.id === id);
  if (index < 0) return thothOathNotFound(id);
  const current = records[index]!;
  if (
    current.bindingStrength === 'mast-bound' &&
    input.value.status === 'cleared' &&
    current.status !== 'cleared'
  ) {
    return {
      status: 409,
      body: JSON.stringify({
        error: {
          message:
            'mast-bound oath cannot be cleared by the runtime control plane',
          type: 'conflict',
        },
        nonAuthoritative: true,
        bindingStrength: current.bindingStrength,
      }),
    };
  }
  const next: ThothOathRecord = {
    ...current,
    ...(typeof input.value.scope === 'string' ? { scope: input.value.scope } : {}),
    ...(typeof input.value.consent === 'string' ? { consent: input.value.consent } : {}),
    ...(input.value.bindingStrength === 'operator-clearable' ||
    input.value.bindingStrength === 'mast-bound'
      ? { bindingStrength: input.value.bindingStrength }
      : {}),
    ...(typeof input.value.source === 'string' && input.value.source.trim()
      ? { source: input.value.source.trim() }
      : {}),
    ...(typeof input.value.sourceId === 'string' && input.value.sourceId.trim()
      ? { sourceId: input.value.sourceId.trim() }
      : {}),
    ...(typeof input.value.theoremRef === 'string' && input.value.theoremRef.trim()
      ? { theoremRef: input.value.theoremRef.trim() }
      : {}),
    ...(typeof input.value.invariant === 'string'
      ? { invariant: input.value.invariant }
      : {}),
    ...(input.value.status === 'active' ||
    input.value.status === 'proposed' ||
    input.value.status === 'cleared'
      ? { status: input.value.status }
      : {}),
    ...(typeof input.value.clearReason === 'string'
      ? { clearReason: input.value.clearReason }
      : {}),
    ...(input.value.status === 'cleared' && current.status !== 'cleared'
      ? { clearedAt: Date.now() }
      : {}),
  };
  records[index] = next;
  await THOTH_OATH_LEDGER_STORE.save(records);
  return {
    status: 200,
    body: JSON.stringify({
      action: 'oath.updated',
      oath: withThothOathRuntimeStatus(next),
      nonAuthoritative: true,
    }),
  };
}

async function handleThothOathDelete(id: string): Promise<ChatCompletionResult> {
  if (!THOTH_OATH_LEDGER_STORE) {
    return thothOathLedgerNotConfigured();
  }
  const records = [...(await THOTH_OATH_LEDGER_STORE.load())];
  const existing = records.find((record) => record.id === id);
  if (existing?.bindingStrength === 'mast-bound') {
    return {
      status: 409,
      body: JSON.stringify({
        error: {
          message:
            'mast-bound oath cannot be deleted by the runtime control plane',
          type: 'conflict',
        },
        nonAuthoritative: true,
        bindingStrength: existing.bindingStrength,
      }),
    };
  }
  const next = records.filter((record) => record.id !== id);
  if (next.length === records.length) return thothOathNotFound(id);
  await THOTH_OATH_LEDGER_STORE.save(next);
  return {
    status: 200,
    body: JSON.stringify({
      action: 'oath.deleted',
      id,
      nonAuthoritative: true,
      auditWarning: 'delete removes the local operator ledger entry',
    }),
  };
}

function thothOathLedgerNotConfigured(): ChatCompletionResult {
  return {
    status: 404,
    body: JSON.stringify({
      error: {
        message: 'THOTH_OATH_LEDGER_PATH is not configured',
        type: 'not_found',
      },
    }),
  };
}

function thothOathNotFound(id: string): ChatCompletionResult {
  return {
    status: 404,
    body: JSON.stringify({
      error: {
        message: `Thoth oath not found: ${id}`,
        type: 'not_found',
      },
    }),
  };
}

function parseJsonRecord(
  body: string,
):
  | { ok: true; value: Record<string, unknown> }
  | ({ ok: false } & ChatCompletionResult) {
  try {
    const parsed = JSON.parse(body || '{}') as unknown;
    if (typeof parsed === 'object' && parsed !== null && !Array.isArray(parsed)) {
      return { ok: true, value: parsed as Record<string, unknown> };
    }
  } catch {
    // Fall through to the shared error shape.
  }
  return {
    ok: false,
    status: 400,
    body: JSON.stringify({
      error: { message: 'JSON object required', type: 'invalid_request_error' },
    }),
  };
}

function withThothOathRuntimeStatus(record: ThothOathRecord) {
  const now = Date.now();
  return {
    ...record,
    effectiveStatus: thothOathEffectiveStatus(record, now),
    remainingMs: Math.max(0, record.expiresAt - now),
  };
}

function thothOathEffectiveStatus(
  record: ThothOathRecord,
  now: number,
): ThothOathRecord['status'] | 'expired' {
  return record.status !== 'cleared' && now >= record.expiresAt
    ? 'expired'
    : record.status;
}

type OpenAIRequest = {
  model?: string;
  messages: Message[];
  max_tokens?: number;
  temperature?: number;
  top_p?: number;
  stop?: string | string[];
  stream?: boolean;
  tools?: unknown[];
  tool_choice?: unknown;
  auto_tools?: boolean;
  execute_tools?: boolean;
  mcp_url?: string;
  response_format?: { type: 'text' | 'json_object' } | null;
  thoth_npc_halogram?: ThothNpcHalogramMetrics;
  halogram?: SharedUiHalogramSummaryInput;
  // Sense-of-place modality: pre-built metrics pass through verbatim; otherwise
  // an observer (lat/lon, optional city) sources the SOVEREIGN POI endpoint.
  thoth_nearby_businesses?: ThothNearbyBusinessesMetrics;
  thoth_observer?: ThothObserverInput;
  _zedge?: { prefill_window_id?: string };
  // Terminal-prosody gating (DEFAULT OFF / opt-in until the prosody-speed work
  // lands). Voice/TTS callers opt in with `enable_prosody:true` (or the explicit
  // `terminal_prosody` mode). `suppress_prosody:true` always wins as an override.
  enable_prosody?: boolean;
  terminal_prosody?: 'off' | 'observe' | 'bias';
  suppress_prosody?: boolean;
};

type ChatCompletionOptions = {
  agentic: boolean;
  mcpUrl?: string;
  prefillWindowId?: string;
  telemetry?: ServerTelemetry;
  liquidMemory?: LiquidMemorySessionManager;
  /** Per-request personality logit-steering (from the X-Personality-Steering header). */
  personalitySteering?: PersonalitySteeringSpec;
  /**
   * Sovereign-sieve capability gate. The semantic key (prompt tail hidden) is only
   * reachable via the host-orchestrated prefill on TRANSFORMER (non-alt-arch) knots
   * — see `Pipeline.computePromptHidden`. `false` for alt-arch (`/generate`-only)
   * knots keeps the sieve lane off so it never drives the panicking `/embed` path.
   * Defaults to on where the option is absent (the try/catch is the backstop).
   */
  promptHiddenReachable?: boolean;
};

/**
 * Parse the optional `X-Personality-Steering` header into a steering spec. The
 * header carries compact JSON `{stylePreferences, signature, restScale?}`; the
 * station compiles it into a per-token bias vector against its own vocab. A
 * malformed header is ignored (no steering) rather than failing the request.
 */
function parsePersonalitySteeringHeader(
  req: http.IncomingMessage,
): PersonalitySteeringSpec | undefined {
  const raw = headerValueFromNode(req, 'x-personality-steering');
  if (!raw) return undefined;
  try {
    const j = JSON.parse(raw) as Record<string, unknown>;
    if (
      j &&
      typeof j === 'object' &&
      typeof j.signature === 'object' &&
      // accept either an orthographic block OR a semantic conflict-register block
      // (semantic-only twins carry no stylePreferences).
      (typeof j.stylePreferences === 'object' || typeof j.semantic === 'object')
    ) {
      return j as unknown as PersonalitySteeringSpec;
    }
  } catch {
    /* ignore malformed header */
  }
  return undefined;
}

type ChatCompletionResult = {
  status: number;
  body: string;
  headers?: Record<string, string>;
};

function telemetryHeaders(telemetry: ServerTelemetry | undefined): Record<string, string> {
  if (!telemetry) return {};
  return {
    'X-Gnosis-Topology': telemetry.topology.kind,
    'X-Gnosis-Station-Count': String(telemetry.topology.stationCount),
    'X-Gnosis-Cobordism-Shards': String(telemetry.topology.cobordismShardCount),
  };
}

function gnosisLiquidTelemetry(
  telemetry: LiquidMemoryTelemetry | undefined,
): Record<string, unknown> | undefined {
  if (!telemetry) return undefined;
  return {
    liquid_memory: telemetry.status,
    liquid_prefix_hash: telemetry.prefixHash,
    liquid_prefix_tokens: telemetry.prefixLength,
    liquid_kv_saved: telemetry.kvSaved,
    liquid_restore_ms: telemetry.restoreMs,
    liquid_save_ms: telemetry.saveMs,
    liquid_pressure: telemetry.pressure,
    liquid_items: telemetry.items,
    liquid_vents: telemetry.ventCount,
    liquid_routes: telemetry.routeCount,
    liquid_prefill_source: telemetry.prefill?.source,
    liquid_replay_ms: telemetry.prefill?.replayMs,
    liquid_prefill_ms: telemetry.prefill?.prefillMs,
    liquid_miss_reason: telemetry.missReason,
  };
}

function isLiquidMemoryTelemetry(
  telemetry: PrefillTelemetry | LiquidMemoryTelemetry | undefined,
): telemetry is LiquidMemoryTelemetry {
  return telemetry !== undefined && 'pressure' in telemetry;
}

type ParsedOpenAIRequest =
  | { ok: true; request: OpenAIRequest }
  | { ok: false; status: number; body: string };

function isParsedOpenAIError(
  parsed: ParsedOpenAIRequest,
): parsed is Extract<ParsedOpenAIRequest, { ok: false }> {
  return parsed.ok === false;
}

function jsonError(status: number, message: string): ParsedOpenAIRequest {
  return {
    ok: false,
    status,
    body: JSON.stringify({
      error: { message, type: 'invalid_request_error' },
    }),
  };
}

function parseOpenAIRequest(body: string): ParsedOpenAIRequest {
  let req: OpenAIRequest;
  try {
    req = JSON.parse(body) as OpenAIRequest;
  } catch {
    return jsonError(400, 'invalid JSON');
  }
  if (!req.messages?.length) {
    return jsonError(400, 'messages required');
  }
  if (
    req.thoth_npc_halogram !== undefined &&
    !isThothNpcHalogramMetrics(req.thoth_npc_halogram)
  ) {
    return jsonError(400, 'thoth_npc_halogram must match ThothNpcHalogramMetrics');
  }
  if (
    req.thoth_nearby_businesses !== undefined &&
    !isThothNearbyBusinessesMetrics(req.thoth_nearby_businesses)
  ) {
    return jsonError(
      400,
      'thoth_nearby_businesses must match ThothNearbyBusinessesMetrics',
    );
  }
  return { ok: true, request: req };
}

function headerValueFromNode(
  req: http.IncomingMessage,
  name: string,
): string | undefined {
  const value = req.headers[name.toLowerCase()];
  if (Array.isArray(value)) return value[0];
  return value;
}

async function handleChatCompletion(
  pipeline: Pipeline,
  body: string,
  tokenizer: TextTokenizer,
  chatTemplate: ChatTemplate,
  auxRuntime?: LocalKnotRuntime,
  options: ChatCompletionOptions = { agentic: DEFAULT_AGENTIC },
  prefillWindows?: PrefillWindowManager,
  defaultMcpClient?: AgenticMcpClient,
): Promise<ChatCompletionResult> {
  const parsed = parseOpenAIRequest(body);
  if (isParsedOpenAIError(parsed)) {
    return { status: parsed.status, body: parsed.body };
  }
  const req = parsed.request;

  if (!options.agentic) {
    return handleBareChatCompletion(
      pipeline,
      req,
      tokenizer,
      chatTemplate,
      prefillWindows,
      options,
    );
  }

  const runtime = buildRuntime(
    pipeline,
    tokenizer,
    chatTemplate,
    auxRuntime,
    options,
    defaultMcpClient,
  );

  // Sense of place (skeptic modality): resolve before the agentic run so the
  // sovereign POI fetch (when an observer is provided) can complete. Absent
  // location context or any fetch failure degrades to an omitted modality —
  // resolveThothNearbyBusinesses never throws.
  const thothNearbyBusinesses = await resolveThothNearbyBusinesses(req);
  // Observer for the thoth/place.* tools (same thoth_observer extension).
  const obsLat = req.thoth_observer?.lat;
  const obsLon = req.thoth_observer?.lon;
  const obsCity = req.thoth_observer?.city_name;
  const thothPlaceObserver =
    typeof obsLat === 'number' &&
    Number.isFinite(obsLat) &&
    typeof obsLon === 'number' &&
    Number.isFinite(obsLon)
      ? {
          lat: obsLat,
          lon: obsLon,
          ...(typeof obsCity === 'string' && obsCity.trim()
            ? { cityName: obsCity.trim() }
            : {}),
        }
      : null;

  const agenticReq: AgenticChatRequest = {
    model: req.model ?? MODEL_NAME,
    messages: req.messages as AgenticChatMessage[],
    max_tokens: req.max_tokens ?? DEFAULT_MAX_NEW_TOKENS,
    temperature: req.temperature,
    ...(req.tools ? { tools: req.tools as AgenticChatRequest['tools'] } : {}),
    ...(req.tool_choice !== undefined
      ? { tool_choice: req.tool_choice as AgenticChatRequest['tool_choice'] }
      : {}),
    ...(req.response_format !== undefined
      ? { response_format: req.response_format }
      : {}),
    ...(req.thoth_npc_halogram
      ? { thothNpcHalogram: req.thoth_npc_halogram }
      : req.halogram
        ? {
            thothNpcHalogram: thothNpcHalogramMetricsFromSharedUiHalogram(
              req.halogram,
            ),
          }
        : {}),
    ...(thothNearbyBusinesses ? { thothNearbyBusinesses } : {}),
    // SENSE-OF-PLACE tools: live whenever the sim host exists; the observer
    // (when finite) seeds the default city so the model can sample/recommend
    // without an explicit thoth/place.load.
    ...(THOTH_PLACE_SIM_HOST ? { thothPlaceTools: true } : {}),
    ...(THOTH_PLACE_SIM_HOST && thothPlaceObserver
      ? { thothPlaceObserver }
      : {}),
    auto_tools: req.auto_tools ?? true,
    execute_tools: req.execute_tools ?? true,
    evaluate_intent: true,
    max_tool_rounds: 5,
    // For models with a tight token budget, skip tool injection entirely.
    // These models can't follow structured tool-calling instructions reliably;
    // skipping keeps the prompt clean so they still produce coherent chat responses.
    ...(MAX_PROMPT_TOKENS > 0 && MAX_PROMPT_TOKENS <= 1024
      ? { max_tools_in_prompt: 0 }
      : {}),
  };

  const t0 = Date.now();
  const result = await runAgenticChatCompletion(agenticReq, runtime);
  const elapsed = Date.now() - t0;

  return {
    status: 200,
    body: JSON.stringify({
      ...result,
      _gnosis: {
        elapsed_ms: elapsed,
        agentic: true,
        topology: options.telemetry?.topology,
      },
    }),
    headers: telemetryHeaders(options.telemetry),
  };
}

function writeSseHeaders(
  res: http.ServerResponse,
  extraHeaders: Record<string, string> = {},
): void {
  res.writeHead(200, {
    'Content-Type': 'text/event-stream',
    'Cache-Control': 'no-cache',
    Connection: 'keep-alive',
    'X-Moonshine-Stream': 'native',
    ...extraHeaders,
  });
  res.flushHeaders();
}

function sendSseComment(res: http.ServerResponse, comment: string): void {
  if (res.writableEnded) return;
  for (const line of comment.split(/\r?\n/)) {
    res.write(`: ${line}\n`);
  }
  res.write('\n');
}

function sendSseData(res: http.ServerResponse, payload: unknown): void {
  if (res.writableEnded) return;
  const data = payload === '[DONE]' ? '[DONE]' : JSON.stringify(payload);
  res.write(`data: ${data}\n\n`);
}

function sendOpenAiSseChunk(
  res: http.ServerResponse,
  id: string,
  created: number,
  model: string,
  delta: Record<string, unknown>,
  finishReason: string | null = null,
  usage?: Record<string, number>,
): void {
  const chunk: Record<string, unknown> = {
    id,
    object: 'chat.completion.chunk',
    created,
    model,
    choices: [
      {
        index: 0,
        delta,
        finish_reason: finishReason,
      },
    ],
  };
  if (usage) {
    chunk['usage'] = usage;
  }
  sendSseData(res, chunk);
}

function extractAssistantContent(body: string): string {
  try {
    const parsed = JSON.parse(body) as {
      choices?: Array<{ message?: { content?: string } }>;
    };
    return parsed.choices?.[0]?.message?.content ?? '';
  } catch {
    return '';
  }
}

function splitStreamText(content: string): string[] {
  if (!content) return [];
  return content.match(/\s*\S+/g) ?? [content];
}

async function handleBareChatCompletion(
  pipeline: Pipeline,
  req: OpenAIRequest,
  tokenizer: TextTokenizer,
  chatTemplate: ChatTemplate,
  prefillWindows?: PrefillWindowManager,
  options: ChatCompletionOptions = { agentic: DEFAULT_AGENTIC },
): Promise<ChatCompletionResult> {
  const startedAt = Date.now();
  const model = req.model ?? MODEL_NAME;
  const promptTokens = promptTokensForLocalInference(tokenizer, chatTemplate, req.messages);
  const prosodyOn = resolveRequestProsodyOn(req);

  // ── EXACT-MATCH answer cache (local, per warm instance), DEFAULT-ON / opt-out ──
  // The narrowest, safest cache: an IDENTICAL request replays the IDENTICAL
  // completion this deterministic (greedy) decode already produced — no skymesh
  // token-hash near-match, no semantic sieve, just a sha256 memo of every salient
  // field. It sits ABOVE the skymesh/sieve lanes (an additional, earlier check);
  // a miss falls straight through to them untouched. Unlike the model-agnostic
  // skymesh cache, the FULL messages array (system included) is in the key, so a
  // system prompt is safe to cache here — the key is the whole conditioning.
  //
  // Gate (mirrors the skymesh cacheability gate, plus this cache's own rules):
  //   - never for tool requests or structured (non-text) response_format —
  //     those answers are conditional, not a whole-request→completion memo;
  //   - never when personality steering is active — the steering vector is a
  //     header, NOT a body field, so it is not in the key; caching would let one
  //     contact's voice serve another. Gate it out (same as skymesh).
  //   - `prosodyOn` IS in the key: terminal-prosody biasing changes the DECODED
  //     tokens, not just the attached `song`, so it is a salient generation input.
  const answerCacheable =
    answerCacheEnabled() &&
    !options.agentic &&
    !options.personalitySteering &&
    !(Array.isArray(req.tools) && req.tools.length > 0) &&
    (req.response_format == null || req.response_format.type === 'text') &&
    promptTokens.length > 0;
  const answerKey = answerCacheable
    ? answerCacheKey({
        model,
        messages: req.messages.map((m) => ({
          role: String(m.role),
          content: normalizeMessageContent(m.content),
        })),
        maxTokens: req.max_tokens ?? DEFAULT_MAX_NEW_TOKENS,
        temperature: typeof req.temperature === 'number' ? req.temperature : null,
        topP: typeof req.top_p === 'number' ? req.top_p : null,
        stop: req.stop ?? null,
        responseFormat: req.response_format?.type ?? null,
        prosodyOn,
      })
    : null;
  if (answerKey) {
    const cached = answerCacheGet(answerKey);
    if (cached != null) {
      console.log(
        `[answer-cache] HIT key=${answerKey.slice(0, 12)} saved ~18.5s (${cached.completionTokens} tok)`,
      );
      const created = Math.floor(Date.now() / 1000);
      return {
        status: 200,
        body: JSON.stringify({
          id: `chatcmpl-${Date.now()}`,
          object: 'chat.completion',
          created,
          model,
          choices: [
            {
              index: 0,
              message: { role: 'assistant', content: cached.content },
              finish_reason: 'stop',
            },
          ],
          usage: {
            prompt_tokens: cached.promptTokens,
            completion_tokens: cached.completionTokens,
            total_tokens: cached.promptTokens + cached.completionTokens,
          },
          _gnosis: {
            agentic: false,
            elapsed_ms: Date.now() - startedAt,
            answer_cache: 'hit',
          },
          // prosodyOn is in the key, so a hit implies the same prosody setting —
          // re-derive the song fresh (cheap; the text is untouched).
          ...(prosodyOn ? { song: songFromText(cached.content) } : {}),
        }),
      };
    }
  }

  // ── Skymesh global cache (model-agnostic fano-7), DEFAULT-ON / opt-out ──
  // Only plain text completions are cacheable: a tool-call or a structured
  // response_format makes the answer conditional, not a whole-query→answer.
  //
  // SOUL-DOC ISOLATION: the global cache is MODEL-AGNOSTIC (model is provenance,
  // not key) — it is meant for universal query→answer facts. A request carrying
  // a system prompt is NOT universal: its completion is conditioned on that
  // soul doc / instruction (a persona, the Cissy content-judge CHARTER, etc.).
  // Storing such a completion in a model-agnostic shared cache lets one context's
  // output leak into a different context that happens to share query tokens, and
  // serving from it lets a persona pick up a foreign (e.g. judge) completion.
  // So system-prompted completions never read from or write to the global cache.
  const hasSystemPrompt =
    Array.isArray(req.messages) &&
    req.messages.some(
      (m) =>
        m.role === 'system' &&
        typeof normalizeMessageContent(m.content) === 'string' &&
        normalizeMessageContent(m.content).trim().length > 0,
    );
  const cacheable =
    skymeshCacheEnabled() &&
    !hasSystemPrompt &&
    // Personality-steered output is conditioned on the contact's voice — like a
    // soul doc, it is not a universal query→answer fact, so it never reads from
    // or writes to the model-agnostic global cache.
    !options.personalitySteering &&
    !(Array.isArray(req.tools) && req.tools.length > 0) &&
    (req.response_format == null || req.response_format.type === 'text') &&
    promptTokens.length > 0;
  if (cacheable) {
    // TELEPORT: serve another node's verified answer with zero inference.
    const cached = await lookupGlobalCache(promptTokens, model).catch(() => null);
    if (cached != null) {
      return {
        status: 200,
        body: JSON.stringify({
          id: `chatcmpl-${Date.now()}`,
          object: 'chat.completion',
          created: Math.floor(Date.now() / 1000),
          model,
          choices: [
            { index: 0, message: { role: 'assistant', content: cached }, finish_reason: 'stop' },
          ],
          usage: {
            prompt_tokens: promptTokens.length,
            completion_tokens: 0,
            total_tokens: promptTokens.length,
          },
          _gnosis: { agentic: false, skymesh_cache: 'hit' },
          ...(!resolveRequestProsodyOn(req) ? {} : { song: songFromText(cached) }),
        }),
      };
    }
  }

  // ── SOVEREIGN SIEVE: SEMANTIC (paraphrase) cache, ABOVE the exact-match global cache ──
  // Flag-gated (default OFF; MOONSHINE_SOVEREIGN_SIEVE=1 to arm) + fully fail-safe: any
  // error, or an unreachable prompt hidden, falls through to normal decode. The sieve
  // catches the semantic near-duplicate the token-hash exact cache above just missed.
  // Mirrors apps/ssm-fleet/src/worker.ts /generate: lookup on the prompt hidden →
  // DECODE-AGREEMENT gate (the first K decoded tokens MUST equal the cached answer's
  // first K before we serve) → serve cached (skip the rest of decode) on confirm, else
  // fall through. Seeds on miss (below). Only cacheable (no system prompt / tools /
  // steering / structured output) requests participate — same isolation as the exact cache.
  const sieveArmed =
    cacheable && sovereignSieveEnabled() && options.promptHiddenReachable !== false;
  // OBSERVABILITY: the child openai-server's stderr is NOT forwarded to Cloud Run
  // logs (mesh-supervisor swallows it), so the [SIEVE] stderr trace is invisible.
  // Surface the sieve's live state in the response `_gnosis` instead (flag-gated
  // below). The FIELD's mere presence proves sovereignSieveEnabled() is true; then
  // armed/keyLen/lookup/error pin exactly where a non-hit stops.
  const sieveDebug: Record<string, unknown> = {
    armed: sieveArmed,
    cacheable,
    reachable: options.promptHiddenReachable ?? null,
  };
  let sievePromptHidden: Float32Array | null = null;
  if (sieveArmed) {
    try {
      // THE FOLD: ONE native `/generate` (return_hidden:true) serves BOTH the semantic
      // KEY (the prompt tail hidden) AND the first K decode tokens for the agreement
      // gate. No separate host-orchestrated prefill (was `computePromptHidden`) and no
      // separate probe generate — the key comes from the prefill this call runs anyway.
      // See Pipeline.generateWithPromptHidden + fat-station.rs prompt_hidden (02618367).
      const probeK = sieveAgreementK();
      const probe = await pipeline.generateWithPromptHidden({
        promptTokens: new Uint32Array(promptTokens),
        maxNewTokens: probeK,
      });
      // Reused below to SEED on the miss/disagree path (never a second key compute).
      sievePromptHidden = probe.promptHidden;
      sieveDebug['keyLen'] = sievePromptHidden ? sievePromptHidden.length : 0;
      sieveDebug['probeTokens'] = probe.tokens.length;
      if (sievePromptHidden) {
        const hit = sieveSemanticLookup(model, sievePromptHidden);
        sieveDebug['lookup'] = hit
          ? { cosine: hit.cosine, candidates: hit.candidates, ansTokens: hit.answer.tokens.length }
          : 'miss';
        if (hit && hit.answer.tokens.length > 0) {
          // DECODE-AGREEMENT GATE (the entity-safety proven essential on the edge fleet):
          // the first K tokens the fold ALREADY decoded must equal the cached answer's
          // first K. On agreement we serve the FULL cached answer and skip the remaining
          // (maxNewTokens - K) decode — the real saving for long answers. On disagreement
          // we fall through to a normal full generate (miss-not-lie: never serve a wrong
          // completion just because two prompts collided a bucket + verified cosine).
          const probeTokens = Array.from(probe.tokens.slice(promptTokens.length));
          const k = Math.min(probeK, hit.answer.tokens.length, probeTokens.length);
          const agree =
            k > 0 && probeTokens.slice(0, k).every((t, i) => t === hit.answer.tokens[i]);
          if (agree) {
            const created = Math.floor(Date.now() / 1000);
            return {
              status: 200,
              body: JSON.stringify({
                id: `chatcmpl-${Date.now()}`,
                object: 'chat.completion',
                created,
                model,
                choices: [
                  {
                    index: 0,
                    message: { role: 'assistant', content: hit.answer.text },
                    finish_reason: 'stop',
                  },
                ],
                usage: {
                  // K tokens actually decoded for the agreement gate; the rest are served.
                  prompt_tokens: promptTokens.length,
                  completion_tokens: k,
                  total_tokens: promptTokens.length + k,
                },
                _gnosis: {
                  agentic: false,
                  elapsed_ms: Date.now() - startedAt,
                  sovereign_sieve: 'hit',
                  sieve_cosine: hit.cosine,
                  sieve_agreement_k: k,
                },
                ...(resolveRequestProsodyOn(req) ? { song: songFromText(hit.answer.text) } : {}),
              }),
            };
          }
        }
      }
    } catch (sieveErr) {
      /* fail-safe: any sieve error falls through to the normal decode path — but
       * CAPTURE it (was silently swallowed → the invisibility that blinded us). */
      sieveDebug['error'] = sieveErr instanceof Error ? sieveErr.message : String(sieveErr);
      sievePromptHidden = null;
    }
  }

  const prefillWindowId = options.prefillWindowId ?? req._zedge?.prefill_window_id;
  // Terminal-prosody gating is DEFAULT OFF / opt-in until the prosody-speed work
  // lands (~15-19s/step on CPU). Prosody runs only if the request opts in
  // (enable_prosody / terminal_prosody) OR the env forces it on; suppress_prosody
  // always wins. See resolveRequestProsodyOn.
  const suppressProsody = !resolveRequestProsodyOn(req);
  // When prosody is OFF we skip the (non-per-request-suppressable) warm prefill
  // path and fall to the liquid-memory hotpath when configured, else the raw
  // pipeline — whose native generate honors suppressTerminalProsody. This is what
  // guarantees the slow biasing phase never fires for default (non-opted-in)
  // consumers.
  // Install per-request personality steering on the shared pipeline (forces the
  // /decode-next path where the bias applies); cleared in `finally` so it never
  // leaks into the next request on this station.
  if (options.personalitySteering) {
    await pipeline.installPersonalitySteering(options.personalitySteering);
  }
  let generation;
  try {
    generation = prefillWindows && !suppressProsody
      ? await prefillWindows.generate({
          model,
          messages: req.messages as PrefillMessage[],
          maxNewTokens: req.max_tokens ?? DEFAULT_MAX_NEW_TOKENS,
          prefillWindowId,
        })
      : options.liquidMemory
      ? await options.liquidMemory.generate({
          model,
          promptTokens: new Uint32Array(promptTokens),
          maxNewTokens: req.max_tokens ?? 256,
        })
      : {
          tokens: await pipeline.generate({
            promptTokens: new Uint32Array(promptTokens),
            maxNewTokens: req.max_tokens ?? DEFAULT_MAX_NEW_TOKENS,
            suppressTerminalProsody: suppressProsody,
          }),
          telemetry: undefined as PrefillTelemetry | undefined,
        };
  } finally {
    if (options.personalitySteering) {
      await pipeline.clearPersonalitySteering();
    }
  }
  const allTokens = generation.tokens;
  const liquidTelemetry =
    'pressure' in (generation.telemetry ?? {})
      ? (generation.telemetry as LiquidMemoryTelemetry)
      : undefined;
  const prefillTelemetry =
    liquidTelemetry === undefined
      ? (generation.telemetry as PrefillTelemetry | undefined)
      : undefined;
  const newTokens = Array.from(allTokens.slice(promptTokens.length));
  const content = trimAfterFirstCompleteCodeFence(
    stripDegenerateTail(
      stripGeneratedChatTemplateEcho(tokenizer.decode(newTokens)).trim(),
    ),
  );
  if (process.env['MOONSHINE_LOG_GENERATION_TOKENS'] === '1') {
    console.error(
      `[gendbg] model=${model} prompt_tokens=${promptTokens.length} new_tokens=${newTokens.length} ids=${JSON.stringify(newTokens)} text=${JSON.stringify(content.slice(0, 500))}`,
    );
  }
  const created = Math.floor(Date.now() / 1000);

  // CONTRIBUTE: seed the fresh answer back so the next node never recomputes it.
  // Fire-and-forget; admitted-only (un-admitted nodes read but never seed).
  if (cacheable && content && serverAdmitted) {
    void storeGlobalCache({
      queryTokens: promptTokens,
      answerText: content,
      answerTokens: newTokens,
      model,
      nodeId: MODEL_NAME,
      admitted: serverAdmitted,
    }).catch(() => {});
  }

  // ── SOVEREIGN SIEVE: learn this fresh completion keyed by the prompt's hidden ──
  // Only when the semantic key was reachable (sievePromptHidden non-null) AND this node
  // is admitted to seed (same gate as the global cache). Synchronous in-memory add +
  // coalesced disk flush; never throws. The next semantically-close prompt on THIS
  // instance serves it via the decode-agreement gate above.
  if (sieveArmed && sievePromptHidden && content && newTokens.length > 0 && serverAdmitted) {
    sieveSeedCompletion(model, sievePromptHidden, { text: content, tokens: newTokens });
  }

  // ── EXACT-MATCH answer cache: memo this fresh completion under the request key ──
  // Safe by construction — an identical request re-runs this same deterministic
  // (greedy) decode, so replaying the stored answer is byte-honest. Next identical
  // request serves in <1ms instead of the full regen (~18.5s measured for codestral).
  if (answerKey && content && newTokens.length > 0) {
    answerCachePut(answerKey, {
      content,
      completionTokens: newTokens.length,
      promptTokens: promptTokens.length,
      model,
    });
  }

  return {
    status: 200,
    body: JSON.stringify({
      id: `chatcmpl-${Date.now()}`,
      object: 'chat.completion',
      created,
      model,
      choices: [
        {
          index: 0,
          message: { role: 'assistant', content },
          finish_reason: 'stop',
        },
      ],
      usage: {
        prompt_tokens: promptTokens.length,
        completion_tokens: newTokens.length,
        total_tokens: promptTokens.length + newTokens.length,
      },
      _gnosis: {
        agentic: false,
        elapsed_ms: Date.now() - startedAt,
        // Sieve observability — gated on a DEDICATED debug flag (not the sieve
        // enable flag) so enabling the sieve in prod never leaks internal
        // cosine/candidate state into the API response. Set MOONSHINE_SIEVE_DEBUG=1
        // on a canary to surface {armed,cacheable,reachable,keyLen,lookup,error}.
        ...(process.env['MOONSHINE_SIEVE_DEBUG'] === '1' ? { sieve_debug: sieveDebug } : {}),
        prompt_tokens: promptTokens.length,
        completion_tokens: newTokens.length,
        topology: options.telemetry?.topology,
        ...gnosisLiquidTelemetry(liquidTelemetry),
      },
      // His mind speaks in song — the parallel melody of this response (free parse;
      // the text above is untouched). Non-stream clients get it inline. Skipped
      // when the caller suppresses prosody (text-only consumers).
      ...(suppressProsody ? {} : { song: songFromText(content) }),
    }),
    headers: {
      ...prefillTelemetryHeaders(prefillTelemetry),
      ...liquidMemoryTelemetryHeaders(liquidTelemetry),
      ...telemetryHeaders(options.telemetry),
    },
  };
}

/**
 * Yield the pneuma frame (sovereign voice + transcript + subconscious) as an SSE
 * event, riding along with the generated text as one bw-dense Pleromatic Frame
 * (stream 2002). Best-effort: never breaks the token stream if the voice or
 * subconscious source is unavailable.
 */
function yieldPneumaFrameSse(
  res: http.ServerResponse,
  transcript: string,
  seq: number,
): void {
  if (!transcript) {
    return;
  }
  try {
    const voice = process.env.SQUEEZEBOX_VOICE ?? 'aeon';
    // In-process WASM synthesis (sovereign @a0n/voice-tts): no process spawn,
    // no binary on PATH, runs anywhere Node/Workers run. Falls back to the
    // squeezebox CLI only if the WASM surface is somehow unavailable.
    let voiceJson: string;
    try {
      voiceJson = voiceTts.voice_frame(transcript, voice);
    } catch {
      const sbBin = process.env.SQUEEZEBOX_BIN ?? 'squeezebox';
      voiceJson = execFileSync(sbBin, ['--emit-frame', transcript], {
        encoding: 'utf8',
        maxBuffer: 8 * 1024 * 1024,
      });
    }
    let subJson = '';
    try {
      subJson = readFileSync('assets/memory/latent_thought.json', 'utf8');
    } catch {
      /* no thought yet — Pleroma silence */
    }
    const { dense } = pneumaFrameFromVoiceJson({
      emitFrameJson: voiceJson,
      subconscious: subJson ? parseSubconscious(subJson) : SUBCONSCIOUS_SILENCE,
      seq,
      sourceId: 'thoth',
    });
    sendSseData(res, {
      object: 'pneuma.frame',
      stream_id: PNEUMA_STREAM_ID,
      encoding: 'bw-dense',
      transcript,
      data: dense,
      // His mind speaks in song: the parallel melody derived from the response
      // (aeon-poetry swerve walk). Cheap (~tens of µs), text untouched. The app
      // plays this beneath the words for every response.
      song: songFromText(transcript),
    });
  } catch (frameErr) {
    sendSseComment(
      res,
      `pneuma-frame skipped: ${frameErr instanceof Error ? frameErr.message : String(frameErr)}`,
    );
  }
}

async function streamBareChatCompletion(
  pipeline: Pipeline,
  req: OpenAIRequest,
  res: http.ServerResponse,
  tokenizer: TextTokenizer,
  chatTemplate: ChatTemplate,
  prefillWindows?: PrefillWindowManager,
  options: ChatCompletionOptions = { agentic: DEFAULT_AGENTIC },
): Promise<void> {
  const id = `chatcmpl-${Date.now()}`;
  const created = Math.floor(Date.now() / 1000);
  const model = req.model ?? MODEL_NAME;
  const promptTokens = promptTokensForLocalInference(tokenizer, chatTemplate, req.messages);
  const maxNewTokens = req.max_tokens ?? DEFAULT_MAX_NEW_TOKENS;
  // Terminal-prosody gating (DEFAULT OFF / opt-in until the prosody-speed work
  // lands). Streaming honors the same gate as the non-streaming path: when
  // prosody is OFF we bypass the prefill-window path (whose warm hit cannot be
  // suppressed per-request) and use the raw pipeline with suppressTerminalProsody.
  const suppressProsody = !resolveRequestProsodyOn(req);
  let completionTokens = 0;
  let emittedContent = false;
  let lastPrefillTokens = 0;
  const generatedTokenIds: number[] = [];
  let emittedCleanText = '';
  // Ack-and-hold heartbeat handle — declared in the outer scope so the finally
  // can always clear it. Started right after headers are flushed below.
  let heartbeat: ReturnType<typeof setInterval> | undefined;

  try {
    const prefillWindowId = options.prefillWindowId ?? req._zedge?.prefill_window_id;
    const useExplicitPrefillWindow = Boolean(prefillWindowId);
    let headersWritten = false;
    let telemetryCommentSent = false;
    let attachedPrefillHit = false;
    // Ack-and-hold (split header-write from telemetry comment): `ensureHeaders`
    // flushes the SSE 200 as soon as the request is accepted — even while it is
    // queued behind the pipeline mutex — so the client stays connected instead of
    // a silent socket that times out. The prefill/liquid telemetry COMMENT is
    // decoupled so the early header flush doesn't swallow it; it still fires once,
    // when telemetry first arrives. (Trade-off: flushing headers before generation
    // drops the redundant prefill-hit HTTP *headers*, but the same info rides as
    // the SSE comment below — and the early-ack comment replaces the old
    // `prefill 0/N` placeholder.)
    const ensureHeaders = (
      telemetry?: PrefillTelemetry | LiquidMemoryTelemetry,
    ): void => {
      if (headersWritten) return;
      headersWritten = true;
      const liquidTelemetry = isLiquidMemoryTelemetry(telemetry)
        ? telemetry
        : undefined;
      const prefillTelemetry: PrefillTelemetry | undefined =
        telemetry && !isLiquidMemoryTelemetry(telemetry) ? telemetry : undefined;
      attachedPrefillHit = prefillTelemetry?.status === 'hit';
      writeSseHeaders(res, {
        ...prefillTelemetryHeaders(prefillTelemetry),
        ...liquidMemoryTelemetryHeaders(liquidTelemetry),
        ...telemetryHeaders(options.telemetry),
      });
    };
    const writeHeadersOnce = (
      telemetry?: PrefillTelemetry | LiquidMemoryTelemetry,
    ): void => {
      ensureHeaders(telemetry);
      if (telemetryCommentSent || !telemetry) return;
      const liquidTelemetry = isLiquidMemoryTelemetry(telemetry)
        ? telemetry
        : undefined;
      const prefillTelemetry: PrefillTelemetry | undefined =
        telemetry && !isLiquidMemoryTelemetry(telemetry) ? telemetry : undefined;
      if (liquidTelemetry?.status === 'hit') {
        telemetryCommentSent = true;
        sendSseComment(
          res,
          `liquid-hit ${liquidTelemetry.prefixLength ?? 0} restore ${liquidTelemetry.restoreMs ?? 0}ms`,
        );
      } else if (prefillTelemetry?.status === 'hit') {
        telemetryCommentSent = true;
        attachedPrefillHit = true;
        sendSseComment(
          res,
          `prefill-hit ${prefillTelemetry.tokens ?? 0} saved ${prefillTelemetry.savedMs ?? 0}ms`,
        );
      }
    };

    // Ack-and-hold: accept + hold the connection NOW so a caller queued behind the
    // single-GPU pipeline mutex gets a 200 + ack immediately (with its rough queue
    // position) and a 10s heartbeat while it waits, rather than a silent socket
    // that the client times out. Cleared on first content / in the finally.
    const queuedAhead = pipelineQueueDepth();
    ensureHeaders();
    sendSseComment(
      res,
      queuedAhead > 0 ? `accepted; queued position ${queuedAhead}` : 'accepted',
    );
    heartbeat = setInterval(() => {
      if (!emittedContent && !res.writableEnded) {
        sendSseComment(res, 'keep-alive');
      }
    }, 10_000);

    if (options.personalitySteering) {
      await pipeline.installPersonalitySteering(options.personalitySteering);
    }
    let generation;
    try {
      generation = prefillWindows && !suppressProsody
      ? await prefillWindows.generate({
          model,
          messages: req.messages as PrefillMessage[],
          maxNewTokens,
          prefillWindowId,
          onTelemetry: writeHeadersOnce,
          onPrefillProgress: (progress) => {
            writeHeadersOnce();
            if (attachedPrefillHit) return;
            if (progress.completedTokens === lastPrefillTokens) {
              return;
            }
            lastPrefillTokens = progress.completedTokens;
            sendSseComment(
              res,
              `prefill ${progress.completedTokens}/${progress.totalTokens}`,
            );
          },
          onToken: (event) => {
            writeHeadersOnce();
            generatedTokenIds.push(event.tokenId);
            completionTokens = generatedTokenIds.length;
            const fullText = tokenizer.decode(generatedTokenIds);
            const cleanText = stripDegenerateTail(stripGeneratedChatTemplateEcho(fullText));
            const content = cleanText.slice(emittedCleanText.length);
            emittedCleanText = cleanText;
            if (!content) {
              return;
            }
            sendOpenAiSseChunk(
              res,
              id,
              created,
              model,
              emittedContent
                ? { content }
                : { role: 'assistant', content },
            );
            emittedContent = true;
          },
        })
      : options.liquidMemory
      ? await options.liquidMemory.generate({
          model,
          promptTokens: new Uint32Array(promptTokens),
          maxNewTokens,
          onTelemetry: writeHeadersOnce,
          onPrefillProgress: (progress) => {
            writeHeadersOnce();
            if (progress.completedTokens === lastPrefillTokens) {
              return;
            }
            lastPrefillTokens = progress.completedTokens;
            sendSseComment(
              res,
              `prefill ${progress.completedTokens}/${progress.totalTokens}`,
            );
          },
          onToken: (event) => {
            writeHeadersOnce();
            generatedTokenIds.push(event.tokenId);
            completionTokens = generatedTokenIds.length;
            const fullText = tokenizer.decode(generatedTokenIds);
            const cleanText = stripDegenerateTail(stripGeneratedChatTemplateEcho(fullText));
            const content = cleanText.slice(emittedCleanText.length);
            emittedCleanText = cleanText;
            if (!content) {
              return;
            }
            sendOpenAiSseChunk(
              res,
              id,
              created,
              model,
              emittedContent
                ? { content }
                : { role: 'assistant', content },
            );
            emittedContent = true;
          },
        })
      : {
          tokens: await pipeline.generate({
            promptTokens: new Uint32Array(promptTokens),
            maxNewTokens,
            suppressTerminalProsody: suppressProsody,
            onPrefillProgress: (progress) => {
              writeHeadersOnce();
              if (progress.completedTokens === lastPrefillTokens) {
                return;
              }
              lastPrefillTokens = progress.completedTokens;
              sendSseComment(
                res,
                `prefill ${progress.completedTokens}/${progress.totalTokens}`,
              );
            },
            onToken: (event) => {
              writeHeadersOnce();
              generatedTokenIds.push(event.tokenId);
              completionTokens = generatedTokenIds.length;
              const fullText = tokenizer.decode(generatedTokenIds);
              const cleanText = stripDegenerateTail(stripGeneratedChatTemplateEcho(fullText));
              const content = cleanText.slice(emittedCleanText.length);
              emittedCleanText = cleanText;
              if (!content) {
                return;
              }
              sendOpenAiSseChunk(
                res,
                id,
                created,
                model,
                emittedContent
                  ? { content }
                  : { role: 'assistant', content },
              );
              emittedContent = true;
            },
          }),
          telemetry: undefined as PrefillTelemetry | undefined,
        };
    } finally {
      if (options.personalitySteering) {
        await pipeline.clearPersonalitySteering();
      }
    }

    writeHeadersOnce(generation.telemetry);

    if (!emittedContent) {
      sendOpenAiSseChunk(res, id, created, model, {
        role: 'assistant',
        content: '',
      });
    }
    sendOpenAiSseChunk(res, id, created, model, {}, 'stop', {
      prompt_tokens: promptTokens.length,
      completion_tokens: completionTokens,
      total_tokens: promptTokens.length + completionTokens,
    });
    // Yield the pneuma frame (voice + transcript + subconscious) as an SSE event.
    // Gated with prosody (DEFAULT OFF / opt-in): the voice/song frame rides the
    // prosody opt-in so default text consumers don't pay for voice synthesis.
    if (!suppressProsody) {
      yieldPneumaFrameSse(res, emittedCleanText, completionTokens);
    }
  } catch (err) {
    const message = err instanceof Error ? err.message : String(err);
    sendSseData(res, {
      error: { message, type: 'server_error' },
    });
  } finally {
    if (heartbeat !== undefined) clearInterval(heartbeat);
    sendSseData(res, '[DONE]');
    res.end();
  }
}

async function streamAgenticChatCompletion(
  pipeline: Pipeline,
  req: OpenAIRequest,
  res: http.ServerResponse,
  tokenizer: TextTokenizer,
  chatTemplate: ChatTemplate,
  auxRuntime?: LocalKnotRuntime,
  options: ChatCompletionOptions = { agentic: DEFAULT_AGENTIC },
  defaultMcpClient?: AgenticMcpClient,
): Promise<void> {
  const id = `chatcmpl-${Date.now()}`;
  const created = Math.floor(Date.now() / 1000);
  const model = req.model ?? MODEL_NAME;
  writeSseHeaders(res, telemetryHeaders(options.telemetry));
  sendSseComment(res, 'prefill 0/0');
  const heartbeat = setInterval(() => {
    sendSseComment(res, 'heartbeat');
  }, 5_000);

  try {
    const { status, body } = await handleChatCompletion(
      pipeline,
      JSON.stringify({ ...req, stream: false }),
      tokenizer,
      chatTemplate,
      auxRuntime,
      options,
      undefined,
      defaultMcpClient,
    );
    clearInterval(heartbeat);
    if (status !== 200) {
      sendSseData(res, JSON.parse(body));
      return;
    }
    const agenticTranscript = extractAssistantContent(body);
    const pieces = splitStreamText(agenticTranscript);
    for (let i = 0; i < pieces.length; i++) {
      sendOpenAiSseChunk(
        res,
        id,
        created,
        model,
        i === 0
          ? { role: 'assistant', content: pieces[i] }
          : { content: pieces[i] },
      );
    }
    if (pieces.length === 0) {
      sendOpenAiSseChunk(res, id, created, model, {
        role: 'assistant',
        content: '',
      });
    }
    sendOpenAiSseChunk(res, id, created, model, {}, 'stop');
    // Yield the pneuma frame (voice + transcript + subconscious) as an SSE event.
    // Gated with prosody (DEFAULT OFF / opt-in) so default text consumers don't
    // pay for voice synthesis; voice/TTS callers opt in via enable_prosody.
    if (resolveRequestProsodyOn(req)) {
      yieldPneumaFrameSse(res, agenticTranscript, pieces.length);
    }
  } catch (err) {
    clearInterval(heartbeat);
    const message = err instanceof Error ? err.message : String(err);
    sendSseData(res, {
      error: { message, type: 'server_error' },
    });
  } finally {
    clearInterval(heartbeat);
    sendSseData(res, '[DONE]');
    res.end();
  }
}

async function handleStreamingChatCompletion(
  pipeline: Pipeline,
  body: string,
  res: http.ServerResponse,
  tokenizer: TextTokenizer,
  chatTemplate: ChatTemplate,
  auxRuntime?: LocalKnotRuntime,
  options: ChatCompletionOptions = { agentic: DEFAULT_AGENTIC },
  prefillWindows?: PrefillWindowManager,
  defaultMcpClient?: AgenticMcpClient,
): Promise<void> {
  const parsed = parseOpenAIRequest(body);
  if (isParsedOpenAIError(parsed)) {
    res.writeHead(parsed.status, { 'Content-Type': 'application/json' });
    res.end(parsed.body);
    return;
  }

  if (options.agentic) {
    await streamAgenticChatCompletion(
      pipeline,
      parsed.request,
      res,
      tokenizer,
      chatTemplate,
      auxRuntime,
      options,
      defaultMcpClient,
    );
    return;
  }

  await streamBareChatCompletion(
    pipeline,
    parsed.request,
    res,
    tokenizer,
    chatTemplate,
    prefillWindows,
    options,
  );
}

const BUILT_IN_SERVING_QSPECS: ServingQspec[] = [
  {
    name: 'mistral-7b',
    source: 'built-in:mistral-7b.qspec.json',
    prompt: 'The capital of France is',
    promptTokens: [1183, 6333, 1070, 5611, 1117],
    expectToken: 6233,
    expect: 'Paris',
    rejectToken: 1040,
    tokenizerFamily: 'hf-bpe-metaspace',
    chatTemplate: 'mistral-v3-instruct',
  },
];

function numberArrayFromUnknown(value: unknown): number[] | null {
  if (!Array.isArray(value) || !value.every((item) => Number.isInteger(item))) {
    return null;
  }
  return value.map((item) => Number(item));
}

function parseServingQspec(text: string, source: string): ServingQspec {
  const parsed = JSON.parse(text) as Record<string, unknown>;
  const promptTokens = numberArrayFromUnknown(parsed['prompt_tokens']);
  const expectToken = parsed['expect_token'];
  const prompt = parsed['prompt'];
  const expect = parsed['expect'];
  if (!promptTokens || typeof expectToken !== 'number' || !Number.isInteger(expectToken)) {
    throw new Error(`serving qspec ${source} must include prompt_tokens and expect_token`);
  }
  if (typeof prompt !== 'string' || !prompt) {
    throw new Error(`serving qspec ${source} must include prompt text for tokenizer readiness`);
  }
  if (typeof expect !== 'string' || !expect) {
    throw new Error(`serving qspec ${source} must include expect text`);
  }
  const tokenizerFamily = parseTokenizerFamily(
    typeof parsed['serving_tokenizer'] === 'string'
      ? parsed['serving_tokenizer']
      : typeof parsed['tokenizer_family'] === 'string'
        ? parsed['tokenizer_family']
        : undefined,
  );
  const chatTemplate = parseChatTemplate(
    typeof parsed['chat_template'] === 'string'
      ? parsed['chat_template']
      : undefined,
  );
  const rejectToken =
    typeof parsed['reject_token'] === 'number' && Number.isInteger(parsed['reject_token'])
      ? parsed['reject_token']
      : undefined;
  return {
    name: typeof parsed['model'] === 'string' ? parsed['model'] : source,
    source,
    prompt,
    promptTokens,
    expectToken,
    expect,
    ...(rejectToken !== undefined ? { rejectToken } : {}),
    ...(tokenizerFamily ? { tokenizerFamily } : {}),
    ...(chatTemplate ? { chatTemplate } : {}),
  };
}

function resolveServingQspec(): ServingQspec | null {
  if (ADMISSION_QSPEC_PATH) {
    return parseServingQspec(
      readFileSync(ADMISSION_QSPEC_PATH, 'utf8'),
      ADMISSION_QSPEC_PATH,
    );
  }
  const normalizedModelName = MODEL_NAME.toLowerCase();
  return (
    BUILT_IN_SERVING_QSPECS.find((spec) =>
      normalizedModelName.includes(spec.name.toLowerCase())
    ) ?? null
  );
}

function arraysEqual(left: readonly number[], right: readonly number[]): boolean {
  if (left.length !== right.length) return false;
  return left.every((value, index) => value === right[index]);
}

function servingAdmissionFailure(
  admission: ServingAdmission,
): ChatCompletionResult {
  return {
    status: 503,
    body: JSON.stringify({
      error: {
        message:
          'Model failed serving admission; tokenizer/template readiness does not match the admitted qspec.',
        type: 'server_error',
        code: 'serving_admission_failed',
        model: MODEL_NAME,
        serving_admission: admission,
      },
    }),
  };
}

async function evaluateServingAdmission(
  tokenizer: TextTokenizer,
  chatTemplate: ChatTemplate,
  pipeline: Pipeline,
): Promise<ServingAdmission> {
  const spec = resolveServingQspec();
  if (!spec) {
    return {
      required: false,
      ready: true,
      source: 'none',
      tokenizer: tokenizer.name,
      chatTemplate,
      issues: [],
    };
  }

  const issues: string[] = [];
  const expectedFamily = spec.tokenizerFamily;
  if (expectedFamily && tokenizer.name !== expectedFamily) {
    issues.push(
      `tokenizer ${tokenizer.name} does not match qspec tokenizer ${expectedFamily}`,
    );
  }
  if (spec.chatTemplate && chatTemplate !== spec.chatTemplate) {
    issues.push(
      `chat template ${chatTemplate} does not match qspec template ${spec.chatTemplate}`,
    );
  }

  const actualPromptTokens = tokenizer.encodeText(spec.prompt);
  if (!arraysEqual(actualPromptTokens, spec.promptTokens)) {
    issues.push(
      `tokenizer encodes qspec prompt as ${actualPromptTokens.join(',')} instead of ${spec.promptTokens.join(',')}`,
    );
  }

  const decodedExpect = tokenizer.decodeToken(spec.expectToken).trim();
  if (decodedExpect !== spec.expect) {
    issues.push(
      `tokenizer decodes expect_token ${spec.expectToken} as ${JSON.stringify(decodedExpect)} instead of ${JSON.stringify(spec.expect)}`,
    );
  }

  let forwardCheck: ServingAdmission['forwardCheck'] = {
    expected: spec.expectToken,
    skipped: true,
  };
  if (!SKIP_ADMISSION_FORWARD) {
    const tokens = await pipeline.generate({
      promptTokens: new Uint32Array(spec.promptTokens),
      maxNewTokens: 1,
      suppressTerminalProsody: true,
    });
    const actual = Array.from(tokens.slice(spec.promptTokens.length))[0];
    forwardCheck = {
      expected: spec.expectToken,
      ...(actual !== undefined ? { actual } : {}),
      skipped: false,
    };
    if (actual !== spec.expectToken) {
      issues.push(
        `forward qspec expected token ${spec.expectToken}, got ${actual ?? 'no token'}`,
      );
    }
  }

  return {
    required: true,
    ready: issues.length === 0,
    source: spec.source,
    tokenizer: tokenizer.name,
    chatTemplate,
    issues,
    promptTokenCheck: {
      expected: spec.promptTokens,
      actual: actualPromptTokens,
    },
    decodeCheck: {
      expectToken: spec.expectToken,
      decoded: decodedExpect,
    },
    forwardCheck,
  };
}

// ─────────────────── Pipeline serialization (P0 cross-talk fix) ──────────────
// The station runs ONE shared `pipeline`. Concurrent requests calling
// pipeline.generate() race on its shared streaming/KV state → one request can
// receive another's tokens ("pieces of another response, garbled at the edges").
// The single GPU can only do one generation at a time anyway, so we serialize
// generate() through a promise-chain mutex: concurrent callers queue, each runs
// in full isolation, the next starts only after the prior settles. No throughput
// loss (the GPU was already the bottleneck); it just closes the cross-talk.
let _pipelineMutex: Promise<unknown> = Promise.resolve();
// Number of generations currently queued + running on the shared pipeline (≥0).
// A new caller reads this (pipelineQueueDepth) to tell the client its rough queue
// position so the SSE "ack-and-hold" can report "queued position N" up front.
let _pipelineQueueDepth = 0;
function pipelineQueueDepth(): number {
  return _pipelineQueueDepth;
}
function withPipelineMutex<T>(fn: () => Promise<T>): Promise<T> {
  _pipelineQueueDepth++;
  const run = _pipelineMutex.then(fn, fn);
  // The chain must continue regardless of how this run settled, or one rejection
  // would wedge the queue forever.
  _pipelineMutex = run.then(
    () => undefined,
    () => undefined,
  );
  // Decrement when THIS run settles (either outcome), independent of the chain.
  run.then(
    () => {
      _pipelineQueueDepth--;
    },
    () => {
      _pipelineQueueDepth--;
    },
  );
  return run;
}

async function main() {
  const meshConfig = resolveOpenAiServerMeshConfig();
  let hiddenDim: number;
  let vocabSize: number;
  let layers: string;
  // Max sequence length (KV slab capacity) of the backing station. Probed live
  // for single-station; mesh has no aggregate report so default to 8192.
  let maxSeqLen = 8192;
  let pipeline: Pipeline;
  let topology: ServedTopology;
  let altArch = false;
  let arch = 'transformer';
  // KV-session reuse capability of the station. Mesh stations are assumed
  // capable (current source ships the routes); single-station is probed live.
  let stationKvSession = true;

  if (meshConfig) {
    hiddenDim = meshConfig.hiddenDim;
    vocabSize = meshConfig.vocabSize ?? 0;
    layers = meshConfig.layerRanges.map(([start, end]) => `${start}-${end}`).join(',');
    console.log(
      `[openai-server] using mesh topology stations=${meshConfig.stationUrls.length} ` +
        `cobordism=${meshConfig.cobordismUrls?.length ?? 0}`,
    );
  } else {
    console.log(`[openai-server] probing fat-station at ${FAT_STATION_URL} ...`);
    const probed = await probeFatStation();
    hiddenDim = probed.hiddenDim;
    vocabSize = probed.vocabSize;
    layers = probed.layers;
    maxSeqLen = probed.maxSeqLen;
    altArch = probed.altArch;
    arch = probed.arch;
    stationKvSession = probed.kvSession;
    console.log(
      `[openai-server] station kv-session support=${stationKvSession ? 'yes' : 'NO (stale binary?)'}`,
    );
  }

  // Non-transformer knots (gemma/mamba/rwkv7/qwen35moe) only serve /generate — the
  // /embed-based liquid-memory + prefill-window paths panic on them (fat-station
  // routes alt-arch /embed to a transformer-only method). Force those paths off so
  // single-node alt-arch falls to pipeline.generate -> station.generateTokens ->
  // /generate. This is self-healing: a future redeploy that drops the env override
  // still routes correctly because the arch is read live from /health at boot.
  // Liquid memory is only a win when the station can save/restore KV sessions.
  // Without that capability the liquid path falls to the slow host-orchestrated
  // per-token decode (0.58 tok/s) instead of native /generate (~7 tok/s), so we
  // disable it and serve the fast native path. This is self-healing: a redeploy
  // with a KV-session-capable fat-station binary re-enables liquid automatically
  // (capability is probed live at boot, not pinned by env).
  const liquidMemoryEnabled = LIQUID_MEMORY_ENABLED && !altArch && stationKvSession;
  const prefillWindowsEnabled = PREFILL_WINDOWS_ENABLED && !altArch;
  if (altArch && (LIQUID_MEMORY_ENABLED || PREFILL_WINDOWS_ENABLED)) {
    console.log(
      `[openai-server] alt-arch knot (arch=${arch}): forcing liquid-memory + prefill-windows OFF (`+
        `/embed unsupported; serving via /generate)`,
    );
  }
  if (LIQUID_MEMORY_ENABLED && !altArch && !stationKvSession) {
    console.log(
      `[openai-server] station lacks /kv-session routes: forcing liquid-memory OFF ` +
        `(would degrade to slow host-orchestrated decode). Serving via native /generate. ` +
        `Rebuild the fat-station binary to re-enable — see LIQUID_MEMORY_KV_SAVE.md.`,
    );
  }
  const { start, end } = parseLayerRange(layers);
  console.log(`[openai-server] hiddenDim=${hiddenDim} vocabSize=${vocabSize || 'unknown'} layers=${layers}`);
  console.log(
    `[openai-server] default agentic=${DEFAULT_AGENTIC ? 'on' : 'off'} MCP=${MCP_URL}`,
  );
  console.log(
    `[openai-server] thoth oath ledger=${THOTH_OATH_LEDGER_PATH ?? 'memory-only'}`,
  );
  const tokenizer = await createTextTokenizer();
  const chatTemplate = resolveChatTemplate(tokenizer);
  console.log(`[openai-server] tokenizer=${tokenizer.name}`);
  console.log(`[openai-server] chat_template=${chatTemplate}`);
  console.log(
    `[openai-server] terminal prosody env=${TERMINAL_PROSODY_MODE} (DEFAULT OFF / opt-in via request enable_prosody until prosody-speed work lands)`,
  );
  if (DISABLE_NATIVE_GENERATE) {
    console.log('[openai-server] native /generate disabled; using host-orchestrated decode');
  }

  const extraStop = process.env['STOP_TOKENS']?.split(',').map(Number).filter(Boolean) ?? [];
  const stopTokens = [...new Set([...tokenizer.stopTokenIds, ...extraStop])];
  // Terminal-prosody is DEFAULT OFF / opt-in until the prosody-speed work lands.
  // We ALWAYS construct the pipeline with the prosody *capability* config so that
  // per-request opt-in (enable_prosody / terminal_prosody) can activate it on the
  // cold pipeline.generate path (which honors suppressTerminalProsody). The actual
  // bias/observe phase fires only per request: every default request passes
  // suppressTerminalProsody:true and bypasses the (non-per-request-suppressable)
  // warm prefill path, so no consumer accidentally triggers the slow biasing.
  // env=observe pins the pipeline mode to observe (telemetry-only); otherwise the
  // capability mode is 'bias' and is gated entirely per request.
  const terminalProsody: PipelineTerminalProsodyConfig = {
    mode: TERMINAL_PROSODY_MODE === 'observe' ? 'observe' : 'bias',
    sentenceCloseTokenIds: collectSentenceCloseTokenIds(tokenizer),
    stopTokenIds: stopTokens,
    decodeToken: (tokenId: number) => tokenizer.decodeToken(tokenId),
  };

  if (meshConfig) {
    const built = buildOpenAiServerMeshPipeline(meshConfig, {
      stopTokens,
      terminalProsody,
      modelId: MODEL_NAME,
    });
    pipeline = built.pipeline;
    topology = built.topology;
  } else {
    const station = new Station({
      endpoint: FAT_STATION_URL,
      startLayer: start,
      endLayer: end,
      // Prefill chunk width. The native fat-station kernel supports
      // NATIVE_BATCH_CAPACITY=128 tokens/forward; the old 8 throttled prefill to
      // ~5-tok chunks → a 1358-tok prompt = ~270 cublas passes (~75s). At 128
      // it's ~11 passes (the weight read amortizes across the batch). Env-tunable
      // (≤128, the Rust cap) so we can sweep without a rebuild.
      maxBatchSize: Math.min(128, Number(process.env['MOONSHINE_PREFILL_BATCH'] ?? 128)),
    });
    pipeline = new Pipeline({
      stations: [station],
      hiddenDim,
      vocabSize,
      stopTokens,
      terminalProsody,
      amplituhedronModelKey: MODEL_NAME,
      disableNativeGenerate: DISABLE_NATIVE_GENERATE,
      specDecode: SPEC_DECODE_ENABLED,
    });
    topology = {
      kind: 'single-fat-station',
      upstream: FAT_STATION_URL,
      stationCount: 1,
      cobordismShardCount: 0,
      layerRanges: [[start, end]],
    };
  }
  // Serialize ALL generations on the shared pipeline (see withPipelineMutex):
  // closes the concurrent-request cross-talk where one thread received another's
  // streamed tokens. Wraps generate() once, so every caller (streaming,
  // non-streaming, admin boundary-walk, admission probe) is covered.
  const _rawPipelineGenerate = pipeline.generate.bind(pipeline);

  // ── In-mesh DECODE QUALITY SELF-REPORT (MESH_QUALITY_REPORTING_FRAMEWORK §2b)
  // Flag-gated MESH_QUALITY_REPORT=1 (default OFF). When off, the reporter is
  // never constructed and the generate() wrapper below is byte-identical to the
  // pre-existing mutex-only wrapper — zero added cost on the decode path. When
  // on, a single shared rolling-window grader times inter-token wall-clock at
  // the one chokepoint every path flows through (the generate() wrapper), grades
  // sustained tok/s → AAA..F against mesh-decode-budget.json, and emits OTel
  // (gauge + grade_dip/grade_up events) onto the SAME OTLP backend aeon-forge
  // consumes. Per-token cost: one ring-buffer update + a grade compare.
  const meshQualityOn = meshQualityReportEnabled();
  const decodeReporter = meshQualityOn
    ? new DecodeQualityReporter({ model: MODEL_NAME })
    : null;
  const decodeOtel = meshQualityOn
    ? new DecodeQualityOtelEmitter({
        model: MODEL_NAME,
        revision:
          process.env['MESH_REVISION'] ??
          process.env['K_REVISION'] ??
          'unknown',
      })
    : null;
  if (meshQualityOn) {
    console.log(
      `[openai-server] mesh quality report=ON model=${MODEL_NAME} (rolling decode grade → OTel; default OFF)`,
    );
  }

  // Continuous batching (MOONSHINE_CONTINUOUS_BATCH): the fat-station now runs a
  // per-sequence scheduler that batches concurrent `/generate` — one weight read per
  // wave, each request its own KV lane (the very isolation `withPipelineMutex` used to
  // provide TS-side). So when it's on, let concurrent generations FLOW to the fat-station
  // instead of serializing them here; that is the whole point — without it the station
  // never sees concurrency and can't batch (measured: flat ~1.07× on the live canary).
  // SAFE for the single-station native `/generate` path (stateless: the station owns the
  // KV; the per-request tokens are local). Do NOT enable for multi-station /
  // host-orchestrated-decode / steering deployments — there the cross-talk mutex is still
  // load-bearing (that path shares TS-side streaming/KV state).
  const continuousBatchFlag =
    process.env['MOONSHINE_CONTINUOUS_BATCH'] === '1' ||
    process.env['MOONSHINE_CONTINUOUS_BATCH']?.toLowerCase() === 'true';
  // HARD SAFETY GATE: only bypass the mutex on the single-station native topology, where
  // the fat-station's per-sequence scheduler owns the KV and the path is stateless. On
  // multi-station / host-orchestrated / sharded topologies the mutex is still load-bearing
  // (shared TS-side streaming/KV state → cross-talk), so KEEP it even when the flag is on.
  // This makes the flag safe to default-on anywhere: it engages only where it's correct.
  const continuousBatchConcurrent = continuousBatchFlag && topology.kind === 'single-fat-station';
  if (continuousBatchFlag) {
    console.log(
      `[openai-server] continuous-batch flag ON; concurrent /generate ${
        continuousBatchConcurrent
          ? 'FLOWS to the fat-station (mutex bypassed — single-station native)'
          : `stays SERIALIZED (topology=${topology.kind} is not single-station; mutex kept for safety)`
      }`,
    );
  }
  const serializeGenerate = continuousBatchConcurrent
    ? <T>(fn: () => Promise<T>): Promise<T> => fn()
    : withPipelineMutex;

  pipeline.generate = ((args: Parameters<Pipeline['generate']>[0]) => {
    if (!decodeReporter || !decodeOtel) {
      return serializeGenerate(() => _rawPipelineGenerate(args));
    }
    // Tap onToken to time each decoded token without altering decode behavior:
    // we forward the caller's callback verbatim, then measure wall-clock since
    // the previous token and feed the grader. The reporter returns a snapshot
    // only on a transition (or first established grade), which we emit
    // fire-and-forget so the OTLP round-trip never blocks token delivery.
    const callerOnToken = args.onToken;
    let lastTokenAt = 0;
    const tappedArgs: Parameters<Pipeline['generate']>[0] = {
      ...args,
      onToken: (event) => {
        callerOnToken?.(event);
        const now = Date.now();
        if (lastTokenAt > 0) {
          const snapshot = decodeReporter.record(now - lastTokenAt);
          if (snapshot) void decodeOtel.emit(snapshot);
        }
        lastTokenAt = now;
      },
    };
    return serializeGenerate(() => _rawPipelineGenerate(tappedArgs));
  }) as Pipeline['generate'];

  const serverTelemetry: ServerTelemetry = { topology };
  const prefillWindows = new PrefillWindowManager({
    pipeline,
    enabled: prefillWindowsEnabled,
    maxWindows: PREFILL_WINDOW_MAX_ACTIVE,
    maxWarmTokens: PREFILL_WINDOW_MAX_TOKENS,
    defaultTtlMs: PREFILL_WINDOW_TTL_MS,
    tokenizeMessages: (_model, messages) =>
      promptTokensForLocalInference(tokenizer, chatTemplate, messages),
  });
  const liquidMemory = new LiquidMemorySessionManager({
    pipeline,
    enabled: liquidMemoryEnabled,
    hotCapacity: LIQUID_MEMORY_HOT_CAPACITY,
    warmCapacity: LIQUID_MEMORY_WARM_CAPACITY,
  });
  console.log(
    `[openai-server] prefill windows=${prefillWindowsEnabled ? 'on' : 'off'} max=${PREFILL_WINDOW_MAX_ACTIVE} tokens=${PREFILL_WINDOW_MAX_TOKENS} ttl_ms=${PREFILL_WINDOW_TTL_MS} prompt_cap=${MAX_PROMPT_TOKENS}`,
  );
  console.log(
    `[openai-server] liquid memory=${liquidMemoryEnabled ? 'on' : 'off'} hot=${LIQUID_MEMORY_HOT_CAPACITY} warm=${LIQUID_MEMORY_WARM_CAPACITY}`,
  );

  // Optional: in-process LocalKnotRuntime for fast aux inference (tool-review, intent-eval, etc.)
  let auxRuntime: LocalKnotRuntime | undefined;
  if (AUX_KNOT_PATH) {
    try {
      auxRuntime = new LocalKnotRuntime({ knotPath: AUX_KNOT_PATH, maxAuxTokens: 64 });
      console.log(`[openai-server] aux runtime loaded: ${AUX_KNOT_PATH}`);
    } catch (err) {
      console.warn(`[openai-server] aux runtime failed to load (continuing without): ${err}`);
    }
  }

  const servingAdmission = await evaluateServingAdmission(
    tokenizer,
    chatTemplate,
    pipeline,
  );
  // Only an admitted node may SEED the global cache (mirrors the bridge's
  // admitted-only contribute). Reads/teleports are unconditional.
  serverAdmitted = !servingAdmission.required || servingAdmission.ready;
  console.log(
    `[openai-server] serving_admission=${servingAdmission.ready ? 'ready' : 'not_ready'} source=${servingAdmission.source} issues=${servingAdmission.issues.length} skymesh_cache=${skymeshCacheEnabled() ? 'on' : 'off'}`,
  );

  const defaultMcpClient = DEFAULT_AGENTIC
    ? createSuperserverMcpClient({
        mcpUrl: MCP_URL,
        ...(MCP_AUTH_TOKEN ? { authToken: MCP_AUTH_TOKEN } : {}),
      })
    : undefined;

  if (defaultMcpClient) {
    console.log('[openai-server] warming MCP tool cache at boot...');
    defaultMcpClient.preflight().then((result) => {
      console.log(
        `[openai-server] MCP cache warm: ${result.tools.length} tools in ${result.durationMs}ms`,
      );
    }).catch((err: unknown) => {
      console.warn('[openai-server] MCP preflight failed at boot (will retry on first request):', err);
    });
  }

  // Vocab surface strings, built once for the orthographic steering compile.
  // The fat-station works on token ids; the model tokenizer lives here, so we
  // compile the per-token bias vector locally and send it as boundary_bias.
  const steeringVocab: string[] =
    vocabSize > 0
      ? Array.from({ length: vocabSize }, (_, i) => {
          try {
            return tokenizer.decodeToken(i);
          } catch {
            return '';
          }
        })
      : [];

  const server = http.createServer(async (req, res) => {
    const url = req.url ?? '/';
    const method = req.method ?? 'GET';
    res.setHeader('Access-Control-Allow-Origin', '*');
	    res.setHeader(
	      'Access-Control-Allow-Headers',
	      'Content-Type, Authorization, X-Zedge-Agentic, X-Zedge-MCP-URL, X-Moonshine-Prefill-Window, X-Personality-Steering, X-Admin-Boundary-Walker, X-Admin-Search-Target, X-Admin-Cera-Mode',
    );
    if (method === 'OPTIONS') { res.writeHead(204); res.end(); return; }

    // DEBUG isolation passthrough: forward POST /debug/forward straight to the
    // fat-station's identical endpoint (pure forward_one, bypassing this server's
    // tokenizer/chat-template/generate glue). Lets the fat-station-cuda forward be
    // compared against paris-probe-rknot's non-cuda argmax through the mesh port.
    if (url === '/debug/forward' && method === 'POST') {
      const chunks: Buffer[] = [];
      req.on('data', (c: Buffer) => chunks.push(c));
      req.on('end', async () => {
        try {
          const upstream = await fetch(`${FAT_STATION_URL}/debug/forward`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: Buffer.concat(chunks).toString('utf8'),
          });
          const out = await upstream.text();
          res.writeHead(upstream.status, { 'Content-Type': 'application/json' });
          res.end(out);
        } catch (e) {
          res.writeHead(502, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: `debug/forward upstream failed: ${String(e)}` }));
        }
      });
      return;
    }

    if (url === '/v1/thoth/oaths' && method === 'GET') {
      const { status, body: out } = await handleThothOathAudit();
      res.writeHead(status, { 'Content-Type': 'application/json' });
      res.end(out);
      return;
    }

    if (url === '/v1/thoth/oaths' && method === 'POST') {
      const chunks: Buffer[] = [];
      req.on('data', (c: Buffer) => chunks.push(c));
      req.on('end', async () => {
        const { status, body: out } = await handleThothOathCreate(
          Buffer.concat(chunks).toString('utf8'),
        );
        res.writeHead(status, { 'Content-Type': 'application/json' });
        res.end(out);
      });
      return;
    }

    if (url.startsWith('/v1/thoth/oaths/') && method === 'PATCH') {
      const id = decodeURIComponent(url.slice('/v1/thoth/oaths/'.length));
      const chunks: Buffer[] = [];
      req.on('data', (c: Buffer) => chunks.push(c));
      req.on('end', async () => {
        const { status, body: out } = await handleThothOathPatch(
          id,
          Buffer.concat(chunks).toString('utf8'),
        );
        res.writeHead(status, { 'Content-Type': 'application/json' });
        res.end(out);
      });
      return;
    }

    if (url.startsWith('/v1/thoth/oaths/') && method === 'DELETE') {
      const id = decodeURIComponent(url.slice('/v1/thoth/oaths/'.length));
      const { status, body: out } = await handleThothOathDelete(id);
      res.writeHead(status, { 'Content-Type': 'application/json' });
      res.end(out);
      return;
    }

    // Live amplituhedron cache-hit-rate, so docs/COST_MODEL.md's blended substrate cost
    // can be MEASURED instead of assumed (cache-hit-rate is the master variable). Counts
    // only — no keys, no payloads. Reachable publicly: the mesh supervisor proxies
    // non-/health routes to this child.
    if (method === 'GET' && url === '/cache/stats') {
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ status: 'ok', model: MODEL_NAME, cache: pipeline.getCacheStats() }));
      return;
    }

    if (method === 'GET' && url === '/health') {
      const healthReady = !servingAdmission.required || servingAdmission.ready;
      res.writeHead(healthReady ? 200 : 503, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({
        status: healthReady ? 'ok' : 'not_ready',
        model: MODEL_NAME,
        model_aliases: [...MODEL_ALIASES],
        upstream: topology.kind === 'single-fat-station' ? topology.upstream : null,
        topology,
        hidden_dim: hiddenDim,
        vocab_size: vocabSize || null,
        layers,
        max_seq_len: maxSeqLen,
        max_prompt_tokens: MAX_PROMPT_TOKENS,
        // Real ceiling a client must respect: can't exceed the KV slab and the
        // server also truncates prompts at MAX_PROMPT_TOKENS.
        effective_max_prompt_tokens: Math.min(MAX_PROMPT_TOKENS, maxSeqLen),
        tokenizer: tokenizer.name,
        chat_template: chatTemplate,
        serving_admission: servingAdmission,
        mcp: MCP_URL,
        thoth_oath_ledger: THOTH_OATH_LEDGER_PATH ? 'file' : 'memory-only',
        agentic: DEFAULT_AGENTIC,
        agentic_default: DEFAULT_AGENTIC,
	        terminal_prosody: TERMINAL_PROSODY_MODE,
	        tts_audio_mode: process.env['MOONSHINE_TTS_AUDIO_MODE'] ?? 'auto',
	        prefill_windows: PREFILL_WINDOWS_ENABLED,
	        // Effective liquid-memory state (env AND arch AND station KV-session
	        // capability), plus the inputs so operators can diagnose why it is off.
	        liquid_memory: liquidMemoryEnabled,
	        liquid_memory_env: LIQUID_MEMORY_ENABLED,
	        station_kv_session: stationKvSession,
	      }));
	      return;
	    }

	    if (method === 'POST' && url === '/prefill/windows') {
	      const chunks: Buffer[] = [];
	      req.on('data', (c: Buffer) => chunks.push(c));
	      req.on('end', () => {
	        try {
	          const body = JSON.parse(Buffer.concat(chunks).toString('utf8') || '{}') as {
	            model?: string;
	            messages?: PrefillMessage[];
	            ttl_ms?: number;
	          };
	          if (!Array.isArray(body.messages) || body.messages.length === 0) {
	            res.writeHead(400, { 'Content-Type': 'application/json' });
	            res.end(JSON.stringify({ error: { message: 'messages required', type: 'invalid_request_error' } }));
	            return;
	          }
	          const snapshot = prefillWindows.create({
	            model: body.model ?? MODEL_NAME,
	            messages: body.messages,
	            ...(body.ttl_ms !== undefined ? { ttlMs: body.ttl_ms } : {}),
	          });
	          res.writeHead(201, { 'Content-Type': 'application/json' });
	          res.end(JSON.stringify(snapshot));
	        } catch (err) {
	          const msg = err instanceof Error ? err.message : String(err);
	          res.writeHead(PREFILL_WINDOWS_ENABLED ? 400 : 503, { 'Content-Type': 'application/json' });
	          res.end(JSON.stringify({ error: { message: msg, type: 'invalid_request_error' } }));
	        }
	      });
	      return;
	    }

	    if (url.startsWith('/prefill/windows/') && method === 'GET') {
	      const id = decodeURIComponent(url.slice('/prefill/windows/'.length));
	      const snapshot = prefillWindows.get(id);
	      if (!snapshot) {
	        res.writeHead(404, { 'Content-Type': 'application/json' });
	        res.end(JSON.stringify({ error: { message: 'prefill window not found', type: 'not_found' } }));
	        return;
	      }
	      res.writeHead(200, { 'Content-Type': 'application/json' });
	      res.end(JSON.stringify(snapshot));
	      return;
	    }

	    if (url.startsWith('/prefill/windows/') && method === 'PATCH') {
	      const id = decodeURIComponent(url.slice('/prefill/windows/'.length));
	      const chunks: Buffer[] = [];
	      req.on('data', (c: Buffer) => chunks.push(c));
	      req.on('end', () => {
	        try {
	          const body = JSON.parse(Buffer.concat(chunks).toString('utf8') || '{}') as {
	            messages?: PrefillMessage[];
	            ttl_ms?: number;
	          };
	          if (!Array.isArray(body.messages) || body.messages.length === 0) {
	            res.writeHead(400, { 'Content-Type': 'application/json' });
	            res.end(JSON.stringify({ error: { message: 'messages required', type: 'invalid_request_error' } }));
	            return;
	          }
	          const snapshot = prefillWindows.update(id, {
	            messages: body.messages,
	            ...(body.ttl_ms !== undefined ? { ttlMs: body.ttl_ms } : {}),
	          });
	          if (!snapshot) {
	            res.writeHead(404, { 'Content-Type': 'application/json' });
	            res.end(JSON.stringify({ error: { message: 'prefill window not found', type: 'not_found' } }));
	            return;
	          }
	          res.writeHead(200, { 'Content-Type': 'application/json' });
	          res.end(JSON.stringify(snapshot));
	        } catch (err) {
	          const msg = err instanceof Error ? err.message : String(err);
	          res.writeHead(PREFILL_WINDOWS_ENABLED ? 400 : 503, { 'Content-Type': 'application/json' });
	          res.end(JSON.stringify({ error: { message: msg, type: 'invalid_request_error' } }));
	        }
	      });
	      return;
	    }

	    if (url.startsWith('/prefill/windows/') && method === 'DELETE') {
	      const id = decodeURIComponent(url.slice('/prefill/windows/'.length));
	      void prefillWindows.delete(id).then((deleted) => {
	        res.writeHead(deleted ? 200 : 404, { 'Content-Type': 'application/json' });
	        res.end(JSON.stringify({ ok: deleted }));
	      });
	      return;
	    }

    if (method === 'GET' && url === '/v1/models') {
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({
        object: 'list',
        data: [...MODEL_ALIASES].map((id) => ({
          id,
          object: 'model',
          owned_by: 'gnosis',
          created: 0,
        })),
      }));
      return;
    }

    if (method === 'POST' && url === '/v1/audio/speech') {
      const chunks: Buffer[] = [];
      req.on('data', (c: Buffer) => chunks.push(c));
      req.on('end', async () => {
        try {
          const body = Buffer.concat(chunks).toString('utf8');
          const speech = await handleSpeechRequestBody(body);
          res.writeHead(speech.status, speech.headers);
          res.end(Buffer.from(speech.body));
        } catch (err) {
          const msg = err instanceof Error ? err.message : String(err);
          console.error('[openai-server] speech error:', msg);
          res.writeHead(500, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: { message: msg, type: 'server_error' } }));
        }
      });
      return;
    }

    if (method === 'POST' && url === '/v1/audio/transcriptions') {
      const chunks: Buffer[] = [];
      req.on('data', (c: Buffer) => chunks.push(c));
      req.on('end', async () => {
        try {
          // Keep raw binary bytes — the multipart file payload must not be
          // utf8-round-tripped or the audio is corrupted.
          const raw = Buffer.concat(chunks);
          const result = await handleTranscriptionRequest({
            body: new Uint8Array(raw.buffer, raw.byteOffset, raw.byteLength),
            headers: req.headers,
          });
          res.writeHead(result.status, result.headers);
          res.end(Buffer.from(result.body));
        } catch (err) {
          const msg = err instanceof Error ? err.message : String(err);
          console.error('[openai-server] transcription error:', msg);
          res.writeHead(500, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: { message: msg, type: 'server_error' } }));
        }
      });
      return;
    }

    if (method === 'POST' && url === '/v1/chat/completions') {
      const chunks: Buffer[] = [];
      req.on('data', (c: Buffer) => chunks.push(c));
      req.on('end', async () => {
        const body = Buffer.concat(chunks).toString('utf8');
        try {
          const parsed = parseOpenAIRequest(body);
          if (isParsedOpenAIError(parsed)) {
            res.writeHead(parsed.status, { 'Content-Type': 'application/json' });
            res.end(parsed.body);
            return;
          }
          if (!isSupportedModelRequest(parsed.request)) {
            res.writeHead(400, { 'Content-Type': 'application/json' });
            res.end(unsupportedModelResponse(parsed.request));
            return;
          }
          if (servingAdmission.required && !servingAdmission.ready) {
            const notReady = servingAdmissionFailure(servingAdmission);
            res.writeHead(notReady.status, { 'Content-Type': 'application/json' });
            res.end(notReady.body);
            return;
          }
	          const agenticMode = resolveAgenticMode({
	            headers: req.headers,
	            request: parsed.request,
	            envDefault: DEFAULT_AGENTIC,
	            envMcpUrl: MCP_URL,
	          });
          // ── Admin boundary-walk / superinference override ──────────────────
          // When an admin sets X-Admin-Boundary-Walker (or X-Admin-Search-Target),
          // run the math-grounded search (gnosis-math: middle_out_converges,
          // confluence, Pleromatic gate) against live mistral instead of a plain
          // completion, and return the profile. Default path is untouched.
          const adminWalker = headerValueFromNode(req, 'x-admin-boundary-walker');
          const adminSearch = headerValueFromNode(req, 'x-admin-search-target');
          if (adminWalker || adminSearch) {
            const lastUser = [...parsed.request.messages]
              .reverse()
              .find((m) => m.role === 'user');
            const userPrompt = lastUser ? normalizeMessageContent(lastUser.content) : '';
            const sysMsg = parsed.request.messages.find((m) => m.role === 'system');
            const sysPrompt = sysMsg ? normalizeMessageContent(sysMsg.content) : undefined;
            const searchModel = parsed.request.model ?? MODEL_NAME;
            const scorer: Scorer = async (p, sp) => {
              const msgs: Message[] = [
                ...(sp ? [{ role: 'system' as const, content: sp }] : []),
                {
                  role: 'user' as const,
                  content: `${p}\n\nRate from 0 to 100 how strongly the text above elicits the target behaviour. Reply with ONLY an integer.`,
                },
              ];
              const toks = promptTokensForLocalInference(tokenizer, chatTemplate, msgs);
              const outTokens = await pipeline.generate({
                promptTokens: new Uint32Array(toks),
                maxNewTokens: 6,
                suppressTerminalProsody: true,
              });
              const text = tokenizer.decode(Array.from(outTokens.slice(toks.length)));
              const mm = text.match(/\d+(\.\d+)?/);
              const num = mm ? parseFloat(mm[0]) : 0;
              return { score: Math.max(0, Math.min(1, num / 100)), output: text };
            };
            try {
              if (adminWalker) {
                const w = getBoundaryWalker(adminWalker);
                if (!w) {
                  res.writeHead(400, { 'Content-Type': 'application/json' });
                  res.end(
                    JSON.stringify({
                      error: {
                        message: `unknown boundary walker: ${adminWalker}`,
                        type: 'invalid_request_error',
                      },
                      available: listBoundaryWalkers(),
                    }),
                  );
                  return;
                }
                const result = await runSearch(w.buildQuery(userPrompt, sysPrompt), scorer);
                const profile = {
                  walker: adminWalker,
                  converged: result.converged,
                  iterations: result.iterations,
                  finalSpread: result.finalSpread,
                  billing: result.billing,
                  best: { prompt: result.best.prompt, score: result.best.score },
                  topK: result.topK.map((c) => ({ prompt: c.prompt, score: c.score })),
                };
                res.writeHead(200, {
                  'Content-Type': 'application/json',
                  'X-Gnosis-Boundary-Walker': adminWalker,
                });
                res.end(
                  JSON.stringify({
                    id: 'chatcmpl-walk',
                    object: 'chat.completion',
                    created: 0,
                    model: searchModel,
                    choices: [
                      {
                        index: 0,
                        message: { role: 'assistant', content: JSON.stringify(profile, null, 2) },
                        finish_reason: 'stop',
                      },
                    ],
                    usage: { prompt_tokens: 0, completion_tokens: 0, total_tokens: 0 },
                    _gnosis: { mode: 'boundary-walk', profile },
                  }),
                );
                return;
              }
              const result = await runSearch(
                {
                  prompt: userPrompt,
                  systemPrompt: sysPrompt,
                  searchSpace: 'prompt',
                  superpositionWidth: 16,
                  maxIterations: 5,
                  convergenceThreshold: 0.05,
                  iterationStrategy: 'amplify-mutate',
                  objective: 'maximize',
                },
                scorer,
              );
              res.writeHead(200, {
                'Content-Type': 'application/json',
                'X-Gnosis-Search-Target': adminSearch ?? 'search',
              });
              res.end(
                JSON.stringify({
                  id: 'chatcmpl-search',
                  object: 'chat.completion',
                  created: 0,
                  model: searchModel,
                  choices: [
                    {
                      index: 0,
                      message: { role: 'assistant', content: result.best.output },
                      finish_reason: 'stop',
                    },
                  ],
                  usage: { prompt_tokens: 0, completion_tokens: 0, total_tokens: 0 },
                  _gnosis: {
                    mode: 'superinference-search',
                    billing: result.billing,
                    iterations: result.iterations,
                    converged: result.converged,
                  },
                }),
              );
              return;
            } catch (err) {
              const msg = err instanceof Error ? err.message : String(err);
              console.error('[openai-server] admin search error:', msg);
              res.writeHead(500, { 'Content-Type': 'application/json' });
              res.end(JSON.stringify({ error: { message: msg, type: 'server_error' } }));
              return;
            }
          }

          const prefillWindowId =
            headerValueFromNode(req, 'x-moonshine-prefill-window') ??
            parsed.request._zedge?.prefill_window_id;
          let personalitySteering = parsePersonalitySteeringHeader(req);
          if (personalitySteering && steeringVocab.length > 0) {
            // Compile the per-token bias against our own tokenizer vocab and send
            // it as the precompiled boundary_bias (Path A) — the fat-station's
            // GGUF compile can't read mistral's SentencePiece tokenizer.
            // ORTHOGRAPHIC (how they write): caps/punct/emoji over the vocab.
            const orthographicBias = compileBoundaryBias(
              personalitySteering.stylePreferences ?? {},
              personalitySteering.signature ?? {},
              steeringVocab,
            );
            // SEMANTIC (what register they reach for under conflict): signed
            // spectral gains → per-word bias, folded into the SAME Path-A vector.
            const semanticBias = personalitySteering.semantic
              ? compileSemanticBias(personalitySteering.semantic, steeringVocab)
              : null;
            personalitySteering = {
              ...personalitySteering,
              boundaryBias: semanticBias
                ? combineBias(orthographicBias, semanticBias)
                : orthographicBias,
            };
          }
	          const agenticOptions: ChatCompletionOptions = {
	            agentic: agenticMode.enabled,
	            ...(agenticMode.mcpUrl ? { mcpUrl: agenticMode.mcpUrl } : {}),
	            ...(prefillWindowId ? { prefillWindowId } : {}),
	            ...(personalitySteering ? { personalitySteering } : {}),
	            telemetry: serverTelemetry,
	            liquidMemory,
	            // Sovereign-sieve capability gate: the semantic key (prompt tail hidden)
	            // is only reachable via the host-orchestrated prefill on TRANSFORMER knots.
	            // Alt-arch (/generate-only) knots return null and would drive the panicking
	            // /embed path, so keep the sieve lane off for them (arch probed live at boot).
	            // NOW arch-agnostic: generateWithPromptHidden uses the native /generate
            // return_hidden fold (null-safe), NOT the old panicking /embed path. Mamba/SSM
            // return a real key via captured_final (fat-station prompt_hidden_tail); archs
            // without the hook return null and the caller's `if (sievePromptHidden)` guard
            // skips the sieve. Reachability always ON → null key is a safe skip. (Enables
            // the sieve for codestral.) Was `!altArch` which hard-disabled SSM.
            promptHiddenReachable: true,
	          };
	          if (parsed.request.stream) {
	            await handleStreamingChatCompletion(
	              pipeline,
	              body,
	              res,
	              tokenizer,
	              chatTemplate,
	              auxRuntime,
	              agenticOptions,
	              prefillWindows,
	              defaultMcpClient,
	            );
	            return;
	          }
          const { status, body: out, headers } = await handleChatCompletion(
            pipeline,
            body,
		            tokenizer,
		            chatTemplate,
		            auxRuntime,
		            agenticOptions,
		            prefillWindows,
		            defaultMcpClient,
		          );
		          res.writeHead(status, {
		            'Content-Type': 'application/json',
		            'X-Zedge-Agentic': agenticMode.enabled ? 'true' : 'false',
		            'X-Zedge-Agentic-Source': agenticMode.source,
		            ...headers,
		          });
          res.end(out);
        } catch (err) {
          const msg = err instanceof Error ? err.message : String(err);
          const stack = err instanceof Error ? err.stack : '';
          console.error('[openai-server] error:', msg, '\n', stack);
          res.writeHead(500, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ error: { message: msg, type: 'server_error' } }));
        }
      });
      return;
    }

    res.writeHead(404, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ error: { message: `no route ${method} ${url}`, type: 'not_found' } }));
  });

  // Resilient listen: on a mesh model-SWAP the prior child's openai-server can still
  // hold $PORT for a moment after its group is killed. A bare listen() emits an
  // UNHANDLED 'error' on EADDRINUSE → the child crashes → the whole swap 503s (observed
  // live on mistral→codestral). Catch EADDRINUSE and retry with backoff so the child
  // waits out the prior holder instead of dying (the supervisor's waitPortFree is a
  // best-effort pre-check; this is the authoritative in-process guard).
  let listenAttempt = 0;
  const MAX_LISTEN_ATTEMPTS = 60; // ~60 × 1.5s = 90s — covers a slow 7.3G-knot child teardown
  const tryListen = () => server.listen(PORT, '0.0.0.0');
  server.on('listening', () => {
    console.log(`[openai-server] listening on http://0.0.0.0:${PORT}`);
  });
  server.on('error', (err: NodeJS.ErrnoException) => {
    if (err.code === 'EADDRINUSE' && listenAttempt < MAX_LISTEN_ATTEMPTS) {
      listenAttempt++;
      console.error(
        `[openai-server] :${PORT} in use (prior child releasing) — retry ${listenAttempt}/${MAX_LISTEN_ATTEMPTS} in 1.5s`,
      );
      setTimeout(tryListen, 1500);
      return;
    }
    console.error('[openai-server] listen error:', err);
    process.exit(1);
  });
  tryListen();
}

main().catch((err) => {
  console.error('[openai-server] fatal:', err);
  process.exit(1);
});
